accordion.source:
"use client"

import * as React from "react"
import { ChevronDownIcon, ChevronRight } from "lucide-react"
import { Accordion as AccordionPrimitive } from "radix-ui"

import { cn } from "@/lib/utils"

function Accordion({
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Root>) {
  return <AccordionPrimitive.Root data-slot="accordion" {...props} />
}

function AccordionItem({
  className,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Item>) {
  return (
    <AccordionPrimitive.Item
      data-slot="accordion-item"
      className={cn("border-b last:border-b-0", className)}
      {...props}
    />
  )
}

function AccordionTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Trigger>) {
  return (
    <AccordionPrimitive.Header className="flex">
      <AccordionPrimitive.Trigger
        data-slot="accordion-trigger"
        className={cn(
          "focus-visible:border-ring focus-visible:ring-ring/50 flex flex-1 items-start justify-start gap-4 rounded-md py-4 text-left text-sm font-medium transition-all outline-none hover:underline focus-visible:ring-[3px] disabled:pointer-events-none disabled:opacity-50 [&[data-state=open]>svg]:rotate-90",
          className
        )}
        {...props}
      >
        <ChevronRight className="text-muted-foreground pointer-events-none size-4 shrink-0 translate-y-0.5 transition-transform duration-200" />
        {children}
      </AccordionPrimitive.Trigger>
    </AccordionPrimitive.Header>
  )
}

function AccordionContent({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Content>) {
  return (
    <AccordionPrimitive.Content
      data-slot="accordion-content"
      className="data-[state=closed]:animate-accordion-up data-[state=open]:animate-accordion-down overflow-hidden text-sm"
      {...props}
    >
      <div className={cn("pt-0 pb-4", className)}>{children}</div>
    </AccordionPrimitive.Content>
  )
}

export { Accordion, AccordionItem, AccordionTrigger, AccordionContent }

application-shell-4.source:
"use client";

import {
  BadgeCheck,
  BarChart3,
  Briefcase,
  ChevronDown,
  ChevronsUpDown,
  ClipboardList,
  Clock3,
  FileText,
  Folder,
  Globe2,
  HelpCircle,
  LayoutDashboard,
  LogOut,
  Menu,
  Search,
  Settings,
  Sparkles,
  Star,
  User,
  Users,
} from "lucide-react";
import * as React from "react";

import { cn } from "@/lib/utils";

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet";

// Base nav item - used by simple sidebars
type NavItem = {
  label: string;
  icon: React.ComponentType<React.SVGProps<SVGSVGElement>>;
  href: string;
  isActive?: boolean;
  // Optional children for submenus (Sidebar3+)
  children?: NavItem[];
};

// Nav group with optional collapsible state
type NavGroup = {
  title: string;
  items: NavItem[];
  // Optional: default collapsed state (Sidebar2+)
  defaultOpen?: boolean;
};

// User data for footer (Sidebar6+)
type UserData = {
  name: string;
  email: string;
  avatar: string;
};

// Complete sidebar data structure
type SidebarData = {
  // Logo/branding (all sidebars)
  logo: {
    src: string;
    alt: string;
    title: string;
    description: string;
  };
  // Main navigation groups (all sidebars)
  navGroups: NavGroup[];
  // Footer navigation group (all sidebars)
  footerGroup: NavGroup;
  // User data for user footer (Sidebar6+)
  user?: UserData;
  // Workspaces for switcher (Sidebar7+)
  workspaces?: Array<{
    id: string;
    name: string;
    logo: string;
    plan: string;
  }>;
  // Currently active workspace (Sidebar7+)
  activeWorkspace?: string;
};

// Shared sidebar data - works with all sidebar variations
const sidebarData: SidebarData = {
  logo: {
    src: "https://placehold.co/64x64",
    alt: "BlakeUI",
    title: "BlakeUI",
    description: "The best UI library",
  },
  navGroups: [
    {
      title: "Overview",
      defaultOpen: true,
      items: [
        {
          label: "Dashboard",
          icon: LayoutDashboard,
          href: "#",
          isActive: true,
        },
        { label: "Tasks", icon: ClipboardList, href: "#" },
        { label: "Roadmap", icon: BarChart3, href: "#" },
      ],
    },
    {
      title: "Projects",
      defaultOpen: true,
      items: [
        {
          label: "Active Projects",
          icon: Briefcase,
          href: "#",
          children: [
            { label: "Project Alpha", icon: FileText, href: "#" },
            { label: "Project Beta", icon: FileText, href: "#" },
            { label: "Project Gamma", icon: FileText, href: "#" },
          ],
        },
        {
          label: "Archived",
          icon: Folder,
          href: "#",
          children: [
            { label: "2024 Archive", icon: FileText, href: "#" },
            { label: "2023 Archive", icon: FileText, href: "#" },
          ],
        },
      ],
    },
    {
      title: "Team",
      defaultOpen: false,
      items: [
        { label: "Members", icon: Users, href: "#" },
        { label: "Sprints", icon: Clock3, href: "#" },
        { label: "Approvals", icon: BadgeCheck, href: "#" },
        { label: "Reviews", icon: Star, href: "#" },
      ],
    },
    {
      title: "Workspace",
      defaultOpen: false,
      items: [
        { label: "Integrations", icon: Globe2, href: "#" },
        { label: "Automations", icon: Sparkles, href: "#" },
      ],
    },
  ],
  footerGroup: {
    title: "Support",
    items: [
      { label: "Help Center", icon: HelpCircle, href: "#" },
      { label: "Settings", icon: Settings, href: "#" },
    ],
  },
  user: {
    name: "John Doe",
    email: "john@example.com",
    avatar:
      "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/avatar-1.webp",
  },
  workspaces: [
    {
      id: "1",
      name: "Shadcnblocks",
      logo: "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/logos/shadcnblocks-logo.svg",
      plan: "Enterprise",
    },
    {
      id: "2",
      name: "Shadcn Templates",
      logo: "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/logos/shadcnblocks-logo.svg",
      plan: "Startup",
    },
    {
      id: "3",
      name: "Shadcn Components",
      logo: "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/logos/shadcnblocks-logo.svg",
      plan: "Free",
    },
  ],
  activeWorkspace: "1",
};

// Desktop navigation dropdown for each group
const NavDropdown = ({
  group,
  isActive,
  onSelect,
}: {
  group: NavGroup;
  isActive: boolean;
  onSelect: () => void;
}) => {
  return (
    <Button
      variant="secondary"
      className={cn("gap-1", isActive && "bg-brand/95")}
      onClick={onSelect}
    >
      {group.title}
    </Button>
  );
};

// Sub-navigation row showing items for active group
const SubNav = ({
  group,
  activeItem,
  onSelectItem,
}: {
  group: NavGroup;
  activeItem: NavItem | null;
  onSelectItem: (item: NavItem) => void;
}) => {
  return (
    <div className="flex h-10 items-center gap-1 overflow-x-auto border-b bg-muted/30 px-4 lg:px-6">
      {group.items.map((item) => {
        const Icon = item.icon;
        const isActive = activeItem?.label === item.label;
        const hasChildren = item.children && item.children.length > 0;

        if (hasChildren) {
          return (
            <DropdownMenu key={item.label}>
              <DropdownMenuTrigger asChild>
                <Button
                  variant="primary"
                  size="sm"
                  className={cn(
                    "h-7 shrink-0 gap-1.5 text-sm",
                    isActive && "bg-accent text-accent-foreground",
                  )}
                >
                  <Icon className="size-4" />
                  {item.label}
                  <ChevronDown className="size-3" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="start">
                {item.children!.map((child) => {
                  const ChildIcon = child.icon;
                  return (
                    <DropdownMenuItem key={child.label} asChild>
                      <a href={child.href} className="flex items-center gap-2">
                        <ChildIcon className="size-4" />
                        {child.label}
                      </a>
                    </DropdownMenuItem>
                  );
                })}
              </DropdownMenuContent>
            </DropdownMenu>
          );
        }

        return (
          <Button
            key={item.label}
            variant="primary"
            size="sm"
            className={cn(
              "h-7 shrink-0 gap-1.5 text-sm",
              isActive && "bg-accent text-accent-foreground",
            )}
            onClick={() => onSelectItem(item)}
          >
            <Icon className="size-4" />
            {item.label}
          </Button>
        );
      })}
    </div>
  );
};

// Mobile navigation sheet
const MobileNav = ({
  activeGroupIndex,
  onSelectGroup,
}: {
  activeGroupIndex: number;
  onSelectGroup: (index: number) => void;
}) => {
  return (
    <Sheet>
      <SheetTrigger asChild>
        <Button variant="primary" size="sm" className="md:hidden">
          <Menu className="size-5" />
        </Button>
      </SheetTrigger>
      <SheetContent side="left" className="w-72 p-0">
        <SheetHeader className="px-4 pt-4">
          <SheetTitle className="flex items-center gap-2">
            <div className="flex aspect-square size-8 items-center justify-center rounded-sm bg-primary">
              <img
                src={sidebarData.logo.src}
                alt={sidebarData.logo.alt}
                className="size-6 text-primary-foreground invert dark:invert-0"
              />
            </div>
            {sidebarData.logo.title}
          </SheetTitle>
        </SheetHeader>
        <ScrollArea className="min-h-0 flex-1">
          <nav className="flex flex-col gap-4 px-4 py-4">
            {sidebarData.navGroups.map((group, index) => (
              <div key={group.title}>
                <button
                  onClick={() => onSelectGroup(index)}
                  className={cn(
                    "mb-2 text-xs font-medium tracking-wider uppercase",
                    index === activeGroupIndex
                      ? "text-foreground"
                      : "text-muted-foreground",
                  )}
                >
                  {group.title}
                </button>
                {index === activeGroupIndex && (
                  <div className="flex flex-col gap-1">
                    {group.items.map((item) => {
                      const Icon = item.icon;
                      return (
                        <React.Fragment key={item.label}>
                          <a
                            href={item.href}
                            className={cn(
                              "flex items-center gap-2 rounded-md px-2 py-1.5 text-sm hover:bg-muted",
                              item.isActive && "bg-muted font-medium",
                            )}
                          >
                            <Icon className="size-4" />
                            {item.label}
                          </a>
                          {item.children?.map((child) => {
                            const ChildIcon = child.icon;
                            return (
                              <a
                                key={child.label}
                                href={child.href}
                                className="flex items-center gap-2 rounded-md py-1.5 pr-2 pl-8 text-sm hover:bg-muted"
                              >
                                <ChildIcon className="size-4" />
                                {child.label}
                              </a>
                            );
                          })}
                        </React.Fragment>
                      );
                    })}
                  </div>
                )}
              </div>
            ))}
            <Separator />
            <div>
              <div className="mb-2 text-xs font-medium tracking-wider text-muted-foreground uppercase">
                {sidebarData.footerGroup.title}
              </div>
              <div className="flex flex-col gap-1">
                {sidebarData.footerGroup.items.map((item) => {
                  const Icon = item.icon;
                  return (
                    <a
                      key={item.label}
                      href={item.href}
                      className="flex items-center gap-2 rounded-md px-2 py-1.5 text-sm hover:bg-muted"
                    >
                      <Icon className="size-4" />
                      {item.label}
                    </a>
                  );
                })}
              </div>
            </div>
          </nav>
        </ScrollArea>
      </SheetContent>
    </Sheet>
  );
};

// User dropdown
const NavUser = ({ user }: { user: UserData }) => {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="primary" className="gap-2 px-2">
          <Avatar className="size-8">
            <AvatarImage src={user.avatar} alt={user.name} />
            <AvatarFallback>
              {user.name
                .split(" ")
                .map((n) => n[0])
                .join("")}
            </AvatarFallback>
          </Avatar>
          <span className="hidden text-sm font-medium md:inline">
            {user.name}
          </span>
          <ChevronsUpDown className="hidden size-4 md:block" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-56">
        <DropdownMenuLabel className="font-normal">
          <div className="flex flex-col space-y-1">
            <p className="text-sm font-medium">{user.name}</p>
            <p className="text-xs text-muted-foreground">{user.email}</p>
          </div>
        </DropdownMenuLabel>
        <DropdownMenuSeparator />
        <DropdownMenuItem>
          <User className="mr-2 size-4" />
          Account
        </DropdownMenuItem>
        <DropdownMenuSeparator />
        <DropdownMenuItem>
          <LogOut className="mr-2 size-4" />
          Log out
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
};

interface ApplicationShell4Props {
  className?: string;
}

export function ApplicationShell4({ className }: ApplicationShell4Props) {
  const [activeGroupIndex, setActiveGroupIndex] = React.useState(0);
  const activeGroup = sidebarData.navGroups[activeGroupIndex];

  // Initialize activeItem to Dashboard (first item with isActive, or first item)
  const getDefaultActiveItem = (group: NavGroup) => {
    return group.items.find((item) => item.isActive) || group.items[0] || null;
  };

  const [activeItem, setActiveItem] = React.useState<NavItem | null>(
    getDefaultActiveItem(activeGroup),
  );

  return (
    <div className={cn("flex min-h-[520px] flex-col overflow-auto", className)}>
      <div className="flex min-w-fit flex-1 flex-col">
        {/* Top navigation bar */}
        <header className="sticky top-0 z-50 bg-background">
          <div className="flex h-14 items-center gap-2 border-b px-4 sm:gap-4 lg:px-6">
            {/* Mobile menu */}
            <MobileNav
              activeGroupIndex={activeGroupIndex}
              onSelectGroup={setActiveGroupIndex}
            />

            {/* Logo */}
            <a href="#" className="flex shrink-0 items-center gap-2">
              <img
                src={sidebarData.logo.src}
                alt={sidebarData.logo.alt}
                className="size-8 rounded-sm"
              />
              <span className="hidden font-semibold sm:inline">
                {sidebarData.logo.title}
              </span>
            </a>

            {/* Desktop navigation - group tabs */}
            <nav className="ml-4 hidden items-center gap-1 md:flex">
              {sidebarData.navGroups.map((group, index) => (
                <NavDropdown
                  key={group.title}
                  group={group}
                  isActive={index === activeGroupIndex}
                  onSelect={() => setActiveGroupIndex(index)}
                />
              ))}
            </nav>

            {/* Right side */}
            <div className="ml-auto flex shrink-0 items-center gap-2">
              <div className="relative hidden md:block">
                <Search className="absolute top-1/2 left-2.5 size-4 -translate-y-1/2 text-muted-foreground" />
                <Input
                  type="search"
                  placeholder="Search..."
                  className="h-9 w-64 pl-8"
                />
              </div>
              <Button variant="primary" size="sm" className="md:hidden">
                <Search className="size-5" />
              </Button>
              {sidebarData.user && <NavUser user={sidebarData.user} />}
            </div>
          </div>

          {/* Sub-navigation row */}
          <SubNav
            group={activeGroup}
            activeItem={activeItem}
            onSelectItem={setActiveItem}
          />
        </header>

        {/* Main content */}
        <main className="flex flex-1 flex-col gap-4 p-4 lg:p-6">
          <div className="h-[200px] flex-1 rounded-xl bg-muted/50 " />
        </main>
      </div>
    </div>
  );
}

avatar.source:
"use client"

import * as React from "react"
import { Avatar as AvatarPrimitive } from "radix-ui"

import { cn } from "@/lib/utils"

function Avatar({
  className,
  size = "default",
  ...props
}: React.ComponentProps<typeof AvatarPrimitive.Root> & {
  size?: "default" | "sm" | "lg"
}) {
  return (
    <AvatarPrimitive.Root
      data-slot="avatar"
      data-size={size}
      className={cn(
        "group/avatar relative flex size-8 shrink-0 overflow-hidden rounded-full select-none data-[size=lg]:size-10 data-[size=sm]:size-6",
        className
      )}
      {...props}
    />
  )
}

function AvatarImage({
  className,
  ...props
}: React.ComponentProps<typeof AvatarPrimitive.Image>) {
  return (
    <AvatarPrimitive.Image
      data-slot="avatar-image"
      className={cn("aspect-square size-full", className)}
      {...props}
    />
  )
}

function AvatarFallback({
  className,
  ...props
}: React.ComponentProps<typeof AvatarPrimitive.Fallback>) {
  return (
    <AvatarPrimitive.Fallback
      data-slot="avatar-fallback"
      className={cn(
        "bg-muted text-muted-foreground flex size-full items-center justify-center rounded-full text-sm group-data-[size=sm]/avatar:text-xs",
        className
      )}
      {...props}
    />
  )
}

function AvatarBadge({ className, ...props }: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="avatar-badge"
      className={cn(
        "bg-primary text-primary-foreground ring-background absolute right-0 bottom-0 z-10 inline-flex items-center justify-center rounded-full ring-2 select-none",
        "group-data-[size=sm]/avatar:size-2 group-data-[size=sm]/avatar:[&>svg]:hidden",
        "group-data-[size=default]/avatar:size-2.5 group-data-[size=default]/avatar:[&>svg]:size-2",
        "group-data-[size=lg]/avatar:size-3 group-data-[size=lg]/avatar:[&>svg]:size-2",
        className
      )}
      {...props}
    />
  )
}

function AvatarGroup({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="avatar-group"
      className={cn(
        "*:data-[slot=avatar]:ring-background group/avatar-group flex -space-x-2 *:data-[slot=avatar]:ring-2",
        className
      )}
      {...props}
    />
  )
}

function AvatarGroupCount({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="avatar-group-count"
      className={cn(
        "bg-muted text-muted-foreground ring-background relative flex size-8 shrink-0 items-center justify-center rounded-full text-sm ring-2 group-has-data-[size=lg]/avatar-group:size-10 group-has-data-[size=sm]/avatar-group:size-6 [&>svg]:size-4 group-has-data-[size=lg]/avatar-group:[&>svg]:size-5 group-has-data-[size=sm]/avatar-group:[&>svg]:size-3",
        className
      )}
      {...props}
    />
  )
}

export {
  Avatar,
  AvatarImage,
  AvatarFallback,
  AvatarBadge,
  AvatarGroup,
  AvatarGroupCount,
}

badge.source:
import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const badgeVariants = cva(
  "inline-flex max-w-full shrink-0 items-center justify-center gap-1 whitespace-nowrap rounded-[4px] border border-transparent px-[6px] py-[2px] text-xs font-medium leading-none no-underline transition-[color,box-shadow] overflow-hidden [&_svg]:pointer-events-none [&_svg]:inline-block [&_svg]:size-3 [&_svg]:shrink-0 [&_svg]:align-middle focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive",
  {
    variants: {
      variant: {
        default: "bg-badge-default text-badge-default-foreground border-badge-default-border [a&]:hover:bg-badge-default/90",
        secondary:
          "bg-secondary text-secondary-foreground [a&]:hover:bg-secondary/90",
        destructive:
          "bg-destructive text-white [a&]:hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40 dark:bg-destructive/60",
        outline:
          "border-border text-foreground [a&]:hover:bg-accent [a&]:hover:text-accent-foreground",
        ghost: "[a&]:hover:bg-accent [a&]:hover:text-accent-foreground",
        link: "text-primary underline-offset-4 [a&]:hover:underline",
        info: "bg-badge-info text-badge-info-foreground border-badge-info-border [a&]:hover:bg-badge-info/90",
        positive: "bg-badge-positive text-badge-positive-foreground border-badge-positive-border [a&]:hover:bg-badge-positive/90",
        negative: "bg-badge-negative text-badge-negative-foreground border-badge-negative-border [a&]:hover:bg-badge-negative/90",
        warning: "bg-badge-warning text-badge-warning-foreground border-badge-warning-border [a&]:hover:bg-badge-warning/90",
        urgent: "bg-badge-urgent text-badge-urgent-foreground border-badge-urgent-border [a&]:hover:bg-badge-urgent/90",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

function Badge({
  className,
  variant = "default",
  asChild = false,
  ...props
}: React.ComponentProps<"span"> &
  VariantProps<typeof badgeVariants> & { asChild?: boolean }) {
  const Comp = asChild ? Slot : "span"

  return (
    <Comp
      data-slot="badge"
      data-variant={variant}
      className={cn(badgeVariants({ variant }), className)}
      {...props}
    />
  )
}

export { Badge, badgeVariants }

banner.source:
"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { CircleAlertIcon, InfoIcon, XIcon } from "lucide-react";
import { toast } from "sonner";

import { cn } from "@/lib/utils";

const bannerVariants = cva(
  "relative flex w-full items-start gap-3 rounded-[3.5px] border px-4 py-3 text-sm [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default:
          "border-banner-border bg-muted text-banner-text [&>svg]:text-banner-text dark:text-white",
        caution:
          "border-banner-border bg-amber-50 text-banner-text [&_[data-banner-icon]]:text-banner-text dark:border-banner-border dark:bg-amber dark:text-banner-text dark:[&_[data-banner-icon]]:text-banner-text",
        critical:
          "border-banner-border bg-banner-destructive/95 text-banner-text [&_[data-banner-icon]]:text-banner-text",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

function BannerIcon({
  variant,
}: {
  variant: "default" | "caution" | "critical";
}) {
  if (variant === "critical") {
    return <CircleAlertIcon data-banner-icon className="size-4 shrink-0" />;
  }
  return <InfoIcon data-banner-icon className="size-4 shrink-0" />;
}

export interface BannerAction {
  label: React.ReactNode;
  onClick: () => void;
}

export interface BannerProps
  extends
    Omit<React.HTMLAttributes<HTMLDivElement>, "title">,
    VariantProps<typeof bannerVariants> {
  title?: React.ReactNode;
  onClose?: () => void;
  closeLabel?: string;
  /** Optional action button (e.g. "Undo", "View") */
  action?: BannerAction;
}

function Banner({
  className,
  variant = "default",
  title,
  onClose,
  closeLabel = "Close",
  action,
  children,
  ...props
}: BannerProps) {
  return (
    <div
      data-slot="banner"
      data-variant={variant}
      role="alert"
      className={cn(
        bannerVariants({ variant }),
        (onClose || action) && "pe-10",
        className,
      )}
      {...props}
    >
      <BannerIcon variant={variant || "default"} />
      <div className="flex-1 min-w-0">
        {title && <p className="font-medium text-[#30313D] leading-none mb-1">{title}</p>}
        {children && <p className="leading-snug">{children}</p>}
        {action && (
          <button
            type="button"
            onClick={action.onClick}
            className="mt-2 inline-flex h-8 items-center justify-center rounded-md border border-[#D7D7D0] bg-white px-3 text-sm font-medium text-[#30313D] shadow-sm transition-colors hover:bg-muted/80 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 dark:border-[#3d3d45] dark:bg-[#27272a] dark:text-[#f4f4f5] dark:hover:bg-[#3f3f46]"
          >
            {action.label}
          </button>
        )}
      </div>
      {onClose && (
        <button
          type="button"
          aria-label={closeLabel}
          onClick={onClose}
          className="absolute top-3 end-3 rounded-md p-1 opacity-70 transition-opacity hover:opacity-100 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 shrink-0 [&_svg]:text-current"
        >
          <XIcon className="size-4" />
        </button>
      )}
    </div>
  );
}

export { Banner, bannerVariants };

export type BannerVariant = NonNullable<
  VariantProps<typeof bannerVariants>["variant"]
>;

export interface BannerOptions {
  variant?: BannerVariant;
  title?: React.ReactNode;
  description?: React.ReactNode;
  action?: BannerAction;
}

/**
 * Show a persistent banner using the same toast system (Sonner).
 * Banners do not auto-dismiss and show a close button.
 */
function banner(
  message: React.ReactNode,
  options?: BannerOptions,
): string | number {
  const { variant = "default", title, description, action } = options ?? {};
  return toast.custom(
    (id) => (
      <Banner
        variant={variant}
        title={title}
        onClose={() => toast.dismiss(id)}
        closeLabel="Close banner"
        action={
          action
            ? {
                label: action.label,
                onClick: () => {
                  action.onClick();
                  toast.dismiss(id);
                },
              }
            : undefined
        }
      >
        {description ?? message}
      </Banner>
    ),
    { duration: Infinity },
  );
}

export { banner };

