"use client";

import { Line, LineChart, CartesianGrid, XAxis, YAxis } from "recharts";

import { cn } from "@/lib/utils";

import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  type ChartConfig,
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
  ChartLegend,
  ChartLegendContent,
} from "@/components/ui/chart";

interface ChartGroup5Props {
  className?: string;
}

const currentData = [
  { month: "Jan", value: 18600 },
  { month: "Feb", value: 30500 },
  { month: "Mar", value: 23700 },
  { month: "Apr", value: 27300 },
  { month: "May", value: 20900 },
  { month: "Jun", value: 31400 },
];

const previousData = [
  { month: "Jan", value: 15200 },
  { month: "Feb", value: 24800 },
  { month: "Mar", value: 21100 },
  { month: "Apr", value: 22500 },
  { month: "May", value: 19400 },
  { month: "Jun", value: 26200 },
];

const combinedData = currentData.map((item, index) => ({
  month: item.month,
  current: item.value,
  previous: previousData[index].value,
}));

const chartConfig = {
  current: { label: "This Year", color: "var(--chart-1)" },
  previous: { label: "Last Year", color: "var(--chart-4)" },
} satisfies ChartConfig;

const ChartGroup5 = ({ className }: ChartGroup5Props) => {
  const currentTotal = currentData.reduce((sum, item) => sum + item.value, 0);
  const previousTotal = previousData.reduce((sum, item) => sum + item.value, 0);
  const growth = (
    ((currentTotal - previousTotal) / previousTotal) *
    100
  ).toFixed(1);

  return (
    <section className={cn("py-32", className)}>
      <div className="container mx-auto grid gap-4 md:grid-cols-3">
        <Card className="md:col-span-2">
          <CardHeader>
            <CardTitle>Year over Year Comparison</CardTitle>
            <CardDescription>Revenue performance vs last year</CardDescription>
          </CardHeader>
          <CardContent>
            <ChartContainer config={chartConfig} className="h-64 w-full">
              <LineChart
                data={combinedData}
                margin={{ top: 10, right: 10, left: 0, bottom: 0 }}
              >
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis
                  dataKey="month"
                  axisLine={false}
                  tickLine={false}
                  tickMargin={8}
                  fontSize={12}
                />
                <YAxis
                  axisLine={false}
                  tickLine={false}
                  tickMargin={8}
                  fontSize={12}
                  tickFormatter={(v) => `$${v / 1000}k`}
                />
                <ChartTooltip content={<ChartTooltipContent />} />
                <ChartLegend content={<ChartLegendContent />} />
                <Line
                  type="monotone"
                  dataKey="current"
                  stroke="var(--color-current)"
                  strokeWidth={2}
                  dot={{ fill: "var(--color-current)", r: 4 }}
                />
                <Line
                  type="monotone"
                  dataKey="previous"
                  stroke="var(--color-previous)"
                  strokeWidth={2}
                  strokeDasharray="4 4"
                  dot={{ fill: "var(--color-previous)", r: 4 }}
                />
              </LineChart>
            </ChartContainer>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-3">
            <CardTitle>Summary</CardTitle>
            <CardDescription>Period comparison</CardDescription>
          </CardHeader>
          <CardContent className="space-y-3 font-mono text-sm">
            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">This Year</span>
              <span className="font-semibold">
                ${currentTotal.toLocaleString()}
              </span>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">Last Year</span>
              <span className="text-muted-foreground">
                ${previousTotal.toLocaleString()}
              </span>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">Difference</span>
              <span className="text-green-500">
                +${(currentTotal - previousTotal).toLocaleString()}
              </span>
            </div>
            <div className="border-t pt-3">
              <div className="flex items-center justify-between">
                <span className="text-muted-foreground">Growth</span>
                <span className="font-semibold text-green-500">+{growth}%</span>
              </div>
            </div>
            <div className="border-t pt-3 text-xs">
              <div className="flex items-center justify-between">
                <span className="text-muted-foreground">Avg/Month (This)</span>
                <span>${Math.round(currentTotal / 6).toLocaleString()}</span>
              </div>
              <div className="mt-1 flex items-center justify-between">
                <span className="text-muted-foreground">Avg/Month (Last)</span>
                <span className="text-muted-foreground">
                  ${Math.round(previousTotal / 6).toLocaleString()}
                </span>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </section>
  );
};

export { ChartGroup5 };

chart-group-8.source:
"use client";

import { CartesianGrid, XAxis, YAxis, Line, LineChart } from "recharts";
import { TrendingUp, TrendingDown } from "lucide-react";

import { cn } from "@/lib/utils";

import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  type ChartConfig,
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
} from "@/components/ui/chart";

interface ChartGroup8Props {
  className?: string;
}

const weeklyData = [
  { day: "Mon", current: 420, previous: 380 },
  { day: "Tue", current: 510, previous: 450 },
  { day: "Wed", current: 480, previous: 420 },
  { day: "Thu", current: 620, previous: 550 },
  { day: "Fri", current: 710, previous: 620 },
  { day: "Sat", current: 540, previous: 480 },
  { day: "Sun", current: 410, previous: 390 },
];

const performanceData = [
  { metric: "Sales", value: 87, target: 100, fill: "var(--chart-1)" },
  { metric: "Leads", value: 65, target: 100, fill: "var(--chart-2)" },
  { metric: "Conversion", value: 42, target: 100, fill: "var(--chart-3)" },
  { metric: "Retention", value: 91, target: 100, fill: "var(--chart-4)" },
];

const weeklyConfig = {
  current: { label: "This Week", color: "var(--chart-1)" },
  previous: { label: "Last Week", color: "var(--chart-4)" },
} satisfies ChartConfig;

const ChartGroup8 = ({ className }: ChartGroup8Props) => {
  const currentTotal = weeklyData.reduce((sum, d) => sum + d.current, 0);
  const previousTotal = weeklyData.reduce((sum, d) => sum + d.previous, 0);
  const change = (
    ((currentTotal - previousTotal) / previousTotal) *
    100
  ).toFixed(1);
  const isPositive = Number(change) >= 0;

  return (
    <section className={cn("", className)}>
      <div className="container mx-auto grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        {/* Weekly Comparison - spans 2 cols */}
        <Card className="lg:col-span-2">
          <CardHeader className="pb-2">
            <div className="flex items-center justify-between">
              <div>
                <CardTitle className="text-base">Weekly Comparison</CardTitle>
                <CardDescription>This week vs last week</CardDescription>
              </div>
              <div className="text-right">
                <p className="text-2xl font-bold">
                  {currentTotal.toLocaleString()}
                </p>
                <div className="flex items-center justify-end gap-1 text-sm">
                  {isPositive ? (
                    <TrendingUp className="size-4 text-green-500" />
                  ) : (
                    <TrendingDown className="size-4 text-red-500" />
                  )}
                  <span
                    className={isPositive ? "text-green-500" : "text-red-500"}
                  >
                    {isPositive ? "+" : ""}
                    {change}%
                  </span>
                </div>
              </div>
            </div>
          </CardHeader>
          <CardContent>
            <ChartContainer config={weeklyConfig} className="h-52 w-full">
              <LineChart
                data={weeklyData}
                margin={{ top: 10, right: 10, left: 0, bottom: 0 }}
              >
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis
                  dataKey="day"
                  axisLine={false}
                  tickLine={false}
                  tickMargin={8}
                  fontSize={12}
                />
                <YAxis
                  axisLine={false}
                  tickLine={false}
                  tickMargin={8}
                  fontSize={12}
                />
                <ChartTooltip content={<ChartTooltipContent />} />
                <Line
                  type="monotone"
                  dataKey="current"
                  stroke="var(--color-current)"
                  strokeWidth={2}
                  dot={{ fill: "var(--color-current)", r: 4 }}
                />
                <Line
                  type="monotone"
                  dataKey="previous"
                  stroke="var(--color-previous)"
                  strokeWidth={2}
                  strokeDasharray="4 4"
                  dot={{ fill: "var(--color-previous)", r: 3 }}
                />
              </LineChart>
            </ChartContainer>
          </CardContent>
        </Card>

        {/* Monthly Goal Progress */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-base">Monthly Goal</CardTitle>
            <CardDescription>Revenue target progress</CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col items-center justify-center">
            <div className="relative flex size-36 items-center justify-center">
              <svg className="size-full -rotate-90" viewBox="0 0 100 100">
                <circle
                  cx="50"
                  cy="50"
                  r="40"
                  fill="none"
                  className="stroke-muted"
                  strokeWidth="8"
                />
                <circle
                  cx="50"
                  cy="50"
                  r="40"
                  fill="none"
                  className="stroke-chart-1"
                  strokeWidth="8"
                  strokeLinecap="round"
                  strokeDasharray={`${73 * 2.51} ${100 * 2.51}`}
                />
              </svg>
              <div className="absolute flex flex-col items-center">
                <span className="text-2xl font-bold">73%</span>
                <span className="text-xs text-muted-foreground">of goal</span>
              </div>
            </div>
            <p className="mt-2 text-center text-sm text-muted-foreground">
              $36,500 / $50,000
            </p>
          </CardContent>
        </Card>

        {/* Quick Stats */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-base">Quick Stats</CardTitle>
            <CardDescription>Key metrics overview</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            {[
              { label: "Avg. Order", value: "$142", change: 8.5 },
              { label: "New Customers", value: "284", change: 12.3 },
              { label: "Repeat Rate", value: "34%", change: -2.1 },
            ].map((stat, index) => (
              <div key={index} className="flex items-center justify-between">
                <span className="text-sm text-muted-foreground">
                  {stat.label}
                </span>
                <div className="flex items-center gap-2">
                  <span className="font-semibold">{stat.value}</span>
                  <span
                    className={cn(
                      "text-xs",
                      stat.change >= 0 ? "text-green-500" : "text-red-500",
                    )}
                  >
                    {stat.change >= 0 ? "+" : ""}
                    {stat.change}%
                  </span>
                </div>
              </div>
            ))}
          </CardContent>
        </Card>

        {/* Performance Metrics - spans full width */}
        <Card className="lg:col-span-4">
          <CardHeader className="pb-2">
            <CardTitle className="text-base">Performance Metrics</CardTitle>
            <CardDescription>
              Progress towards quarterly targets
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-4">
              {performanceData.map((item, index) => (
                <div key={index} className="space-y-2">
                  <div className="flex items-center justify-between">
                    <span className="text-sm font-medium">{item.metric}</span>
                    <span className="text-sm text-muted-foreground">
                      {item.value}%
                    </span>
                  </div>
                  <div className="h-2 overflow-hidden rounded-full bg-muted">
                    <div
                      className="h-full rounded-full transition-all"
                      style={{
                        width: `${item.value}%`,
                        backgroundColor: item.fill,
                      }}
                    />
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      </div>
    </section>
  );
};

export { ChartGroup8 };

chart.source:
"use client"

import * as React from "react"
import * as RechartsPrimitive from "recharts"

import { cn } from "@/lib/utils"

const THEMES = { light: "", dark: ".dark" } as const

export type ChartConfig = {
  [k in string]: {
    label?: React.ReactNode
    icon?: React.ComponentType<{ className?: string }>
  } & (
    | { color?: string; theme?: never }
    | { color?: never; theme: Record<keyof typeof THEMES, string> }
  )
}

type ChartContextProps = {
  config: ChartConfig
}

const ChartContext = React.createContext<ChartContextProps | null>(null)

function useChart() {
  const context = React.useContext(ChartContext)
  if (!context) {
    throw new Error("useChart must be used within a ChartContainer")
  }
  return context
}

function getPayloadConfigFromPayload(
  config: ChartConfig,
  payload: unknown,
  key: string
) {
  if (typeof payload !== "object" || payload === null) return undefined
  const payloadPayload =
    "payload" in payload &&
    typeof (payload as { payload?: unknown }).payload === "object" &&
    (payload as { payload?: unknown }).payload !== null
    ? (payload as { payload: Record<string, unknown> }).payload
    : undefined

  let configLabelKey: string = key
  const pl = payload as Record<string, unknown>
  if (key in pl && typeof pl[key] === "string") {
    configLabelKey = pl[key] as string
  } else if (
    payloadPayload &&
    key in payloadPayload &&
    typeof payloadPayload[key] === "string"
  ) {
    configLabelKey = payloadPayload[key] as string
  }
  return configLabelKey in config
    ? config[configLabelKey]
    : config[key as keyof typeof config]
}

const ChartContainer = React.forwardRef<
  HTMLDivElement,
  React.ComponentProps<"div"> & {
    config: ChartConfig
    children: React.ReactElement
  }
>(({ id, className, children, config, ...props }, ref) => {
  const uniqueId = React.useId()
  const chartId = `chart-${id ?? uniqueId.replace(/:/g, "")}`

  return (
    <ChartContext.Provider value={{ config }}>
      <div
        ref={ref}
        data-chart={chartId}
        className={cn("w-full", className)}
        {...props}
      >
        <ChartStyle id={chartId} config={config} />
        <RechartsPrimitive.ResponsiveContainer width="100%" height="100%">
          {children}
        </RechartsPrimitive.ResponsiveContainer>
      </div>
    </ChartContext.Provider>
  )
})
ChartContainer.displayName = "ChartContainer"

function ChartStyle({ id, config }: { id: string; config: ChartConfig }) {
  const colorConfig = Object.entries(config).filter(
    ([, c]) => c.theme != null || c.color != null
  )
  if (!colorConfig.length) return null

  const css = Object.entries(THEMES)
    .map(([theme, prefix]) => {
      const selector = prefix ? `${prefix} [data-chart=${id}]` : `[data-chart=${id}]`
      const vars = colorConfig
        .map(([key, itemConfig]) => {
          const color =
            itemConfig.theme?.[theme as keyof typeof itemConfig.theme] ??
            itemConfig.color
          return color ? `  --color-${key}: ${color};` : null
        })
        .filter(Boolean)
        .join("\n")
      return `${selector} {\n${vars}\n}`
    })
    .join("\n\n")

  return <style dangerouslySetInnerHTML={{ __html: css }} />
}

const ChartTooltip = RechartsPrimitive.Tooltip

const ChartTooltipContent = React.forwardRef<
  HTMLDivElement,
  React.ComponentProps<typeof RechartsPrimitive.Tooltip> &
    React.ComponentProps<"div"> & {
      hideLabel?: boolean
      hideIndicator?: boolean
      indicator?: "line" | "dot" | "dashed"
      nameKey?: string
      labelKey?: string
    }
>(
  (
    {
      active,
      payload,
      className,
      indicator = "dot",
      hideLabel = false,
      hideIndicator = false,
      label,
      labelFormatter,
      labelClassName,
      formatter,
      color,
      nameKey,
      labelKey,
    },
    ref
  ) => {
    const { config } = useChart()

    const tooltipLabel = React.useMemo(() => {
      if (hideLabel || !payload?.length) return null
      const [item] = payload
      const key = `${labelKey ?? (item?.dataKey ?? item?.name) ?? "value"}`
      const itemConfig = getPayloadConfigFromPayload(config, item, key)
      const value =
        labelKey == null && typeof label === "string"
          ? config[label as keyof typeof config]?.label ?? label
          : itemConfig?.label
      if (labelFormatter != null) {
        return <>{labelFormatter(value, payload)}</>
      }
      if (value == null) return null
      return <span className={labelClassName}>{value}</span>
    }, [label, labelFormatter, payload, hideLabel, labelClassName, config, labelKey])

    if (!active || !payload?.length) return null

    const nestLabel = payload.length === 1 && indicator !== "dot"

    return (
      <div
        ref={ref}
        className={cn(
          "rounded-lg border bg-popover px-2.5 py-1.5 text-sm text-popover-foreground shadow-md",
          className
        )}
      >
        {!nestLabel ? tooltipLabel : null}
        {payload.map((item, index) => {
          const key = `${nameKey ?? item.name ?? item.dataKey ?? "value"}`
          const itemConfig = getPayloadConfigFromPayload(config, item, key)
          const indicatorColor =
            color ?? (item.payload as { fill?: string })?.fill ?? item.color

          return (
            <div key={item.dataKey ?? index} className="flex items-center gap-2">
              {formatter != null && item?.value !== undefined && item.name != null ? (
                formatter(item.value, item.name, item, index, item.payload)
              ) : (
                <>
                  {itemConfig?.icon != null ? (
                    <itemConfig.icon className="size-4 shrink-0" />
                  ) : (
                    !hideIndicator && (
                      <span
                        className={cn(
                          "rounded-full shrink-0",
                          indicator === "dot" && "size-2.5",
                          indicator === "line" && "h-0.5 w-4",
                          indicator === "dashed" && "h-0.5 w-4 border-t-2 border-dashed"
                        )}
                        style={{
                          backgroundColor:
                            indicator === "dot" ? indicatorColor : undefined,
                          borderColor: indicator === "dashed" ? indicatorColor : undefined,
                        }}
                      />
                    )
                  )}
                  {nestLabel ? tooltipLabel : null}
                  <span>{itemConfig?.label ?? item.name}</span>
                  {item.value != null && (
                    <span className="font-medium tabular-nums">
                      {item.value.toLocaleString()}
                    </span>
                  )}
                </>
              )}
            </div>
          )
        })}
      </div>
    )
  }
)
ChartTooltipContent.displayName = "ChartTooltipContent"

const ChartLegend = RechartsPrimitive.Legend

const ChartLegendContent = React.forwardRef<
  HTMLDivElement,
  React.ComponentProps<typeof RechartsPrimitive.Legend> &
    React.ComponentProps<"div"> & {
      hideIcon?: boolean
      nameKey?: string
    }
>(({ className, hideIcon = false, payload, nameKey }, ref) => {
  const { config } = useChart()
  if (!payload?.length) return null

  return (
    <div
      ref={ref}
      className={cn(
        "flex flex-wrap justify-center gap-4 gap-y-2 [&_svg]:size-3.5",
        className
      )}
    >
      {payload.map((item) => {
        const key = `${nameKey ?? item.dataKey ?? "value"}`
        const itemConfig = getPayloadConfigFromPayload(config, item, key)
        return (
          <div key={item.value} className="flex items-center gap-1.5">
            {itemConfig?.icon != null && !hideIcon ? (
              <itemConfig.icon className="size-4 shrink-0" />
            ) : (
              <span
                className="size-2.5 shrink-0 rounded-full"
                style={{
                  backgroundColor: item.color ?? (item.payload as { fill?: string })?.fill,
                }}
              />
            )}
            <span className="text-muted-foreground text-xs">
              {itemConfig?.label ?? item.value}
            </span>
          </div>
        )
      })}
    </div>
  )
})
ChartLegendContent.displayName = "ChartLegendContent"

export {
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
  ChartLegend,
  ChartLegendContent,
  ChartStyle,
}

