"use client";

import * as React from "react";
import { CheckIcon, MinusIcon } from "lucide-react";
import { Checkbox as CheckboxPrimitive } from "radix-ui";

import { cn } from "@/lib/utils";

interface CheckboxProps extends React.ComponentProps<
  typeof CheckboxPrimitive.Root
> {
  description?: string;
  label?: string;
}

const Checkbox = React.forwardRef<
  React.ElementRef<typeof CheckboxPrimitive.Root>,
  CheckboxProps
>(({ className, description, label, id, ...props }, ref) => {
  const checkbox = (
    <CheckboxPrimitive.Root
      id={id}
      ref={ref}
      data-slot="checkbox"
      className={cn(
        "peer border-input dark:bg-input/30 data-[state=checked]:bg-brand data-[state=checked]:text-primary-foreground dark:data-[state=checked]:bg-brand data-[state=checked]:border-primary data-[state=indeterminate]:bg-brand data-[state=indeterminate]:text-primary-foreground dark:data-[state=indeterminate]:bg-brand data-[state=indeterminate]:border-primary focus-visible:border-ring focus-visible:ring-ring/50 data-[state=checked]:focus-visible:border-ring data-[state=checked]:focus-visible:ring-ring/50 data-[state=indeterminate]:focus-visible:border-ring data-[state=indeterminate]:focus-visible:ring-ring/50 aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive size-4 shrink-0 rounded-[4px] border shadow-xs transition-shadow outline-none focus-visible:ring-[3px] data-[state=checked]:focus-visible:ring-[3px] data-[state=indeterminate]:focus-visible:ring-[3px] disabled:cursor-not-allowed disabled:opacity-50",
        className,
      )}
      {...props}
    >
      <CheckboxPrimitive.Indicator
        data-slot="checkbox-indicator"
        className="grid place-content-center text-current transition-none"
      >
        {props.checked === "indeterminate" ? (
          <MinusIcon className="size-3.5" />
        ) : (
          <CheckIcon className="size-3.5" />
        )}
      </CheckboxPrimitive.Indicator>
    </CheckboxPrimitive.Root>
  );

  if (!label && !description) {
    return checkbox;
  }

  return (
    <div className="flex items-start gap-2">
      {checkbox}
      <div className="grid gap-1.5 leading-none">
        {label && (
          <label
            htmlFor={id}
            className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70"
          >
            {label}
          </label>
        )}
        {description && (
          <p className="text-sm text-muted-foreground">{description}</p>
        )}
      </div>
    </div>
  );
});
Checkbox.displayName = "Checkbox";

export { Checkbox };

chip-menu.source:
"use client";

import * as React from "react";
import { ChevronDownIcon, ChevronLeftIcon, PlusCircleIcon } from "lucide-react";

import { Badge } from "@/components/ui/badge";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { cn } from "@/lib/utils";

export interface ChipMenuOption {
  value: string;
  label: React.ReactNode;
  disabled?: boolean;
}

export interface ChipMenuProps {
  /** Currently selected value (must match an option's value). */
  value: string | null;
  /** Callback when selection changes. */
  onValueChange: (value: string) => void;
  /** Menu options. */
  options: ChipMenuOption[];
  /** Placeholder when no value is selected. */
  placeholder?: string;
  /** Badge variant. */
  variant?: React.ComponentProps<typeof Badge>["variant"];
  /** Optional class for the trigger badge. */
  className?: string;
  /** Optional class for the dropdown content. */
  contentClassName?: string;
  /** Whether the chip is disabled. */
  disabled?: boolean;
}

function ChipMenu({
  value,
  onValueChange,
  options,
  placeholder = "Select…",
  variant = "default",
  className,
  contentClassName,
  disabled = false,
}: ChipMenuProps) {
  const selected = options.find((o) => o.value === value);
  const label = selected ? selected.label : "";
  const [open, setOpen] = React.useState(false);

  const handleReset = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    onValueChange("");
  };

  return (
    <DropdownMenu open={open} onOpenChange={setOpen}>
      {label ? (
        <Badge
          variant={variant}
          className={cn(
            "py-[4px] cursor-pointer gap-1 pr-1 transition-opacity hover:opacity-90 data-[state=open]:opacity-90",
            !selected && "text-muted-foreground",
            className
          )}
        >
          <span
            className="px-[2px] text-chip-menu-placeholder"
            onClick={handleReset}
          >
            <PlusCircleIcon className={cn("size-3 opacity-70 transition-transform", label && "rotate-45")} />{" "}
          </span>
          {placeholder && (
            <span className="text-chip-menu-placeholder">{placeholder}</span>
          )}
          <span className="px-[6px] text-chip-menu-placeholder">|</span>
          <DropdownMenuTrigger
            disabled={disabled}
            className="inline-flex items-center gap-1 h-auto border-0 bg-transparent p-0 outline-none focus:ring-0 focus-visible:ring-0"
          >
            <span className="text-primary">{label}</span>
            <ChevronDownIcon className="size-3 opacity-70" />
          </DropdownMenuTrigger>
        </Badge>
      ) : (
        <DropdownMenuTrigger
          disabled={disabled}
          className="inline-flex h-auto border-0 bg-transparent p-0 outline-none focus:ring-0 focus-visible:ring-0"
        >
          <Badge
            variant={variant}
            className={cn(
              "py-[4px] cursor-pointer gap-1 pr-1 transition-opacity hover:opacity-90 data-[state=open]:opacity-90",
              !selected && "text-muted-foreground",
              className
            )}
          >
            <span className="px-[2px] text-chip-menu-placeholder">
              <PlusCircleIcon className="size-3 opacity-70" />{" "}
            </span>
            {placeholder && (
              <span className="text-chip-menu-placeholder">{placeholder}</span>
            )}
            <span className="text-primary">{label}</span>
            <ChevronDownIcon className="size-3 opacity-70" />
          </Badge>
        </DropdownMenuTrigger>
      )}
      <DropdownMenuContent className={contentClassName} align="start">
        {options.map((opt) => (
          <DropdownMenuItem
            key={opt.value}
            disabled={opt.disabled}
            onSelect={() => onValueChange(opt.value)}
          >
            {opt.label}
          </DropdownMenuItem>
        ))}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

export { ChipMenu };

