"use client";

import * as React from "react";
import {
  type ColumnDef,
  type Header,
  type HeaderGroup,
  type Row,
  type Cell,
  flexRender,
  getCoreRowModel,
  getFilteredRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  useReactTable,
  type SortingState,
} from "@tanstack/react-table";
import { ArrowDown, ArrowUp, ChevronsUpDown } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import {
  NativeSelect,
  NativeSelectOption,
} from "@/components/ui/native-select";

export type OrderFilterRow = {
  id: string;
  orderId: string;
  customer: string;
  orderStatus: string;
  paymentStatus: string;
  total: string;
};

const defaultData: OrderFilterRow[] = [
  {
    id: "1",
    orderId: "ORD-101",
    customer: "Alice",
    orderStatus: "Processing",
    paymentStatus: "Paid",
    total: "$120",
  },
  {
    id: "2",
    orderId: "ORD-102",
    customer: "Bob",
    orderStatus: "Shipped",
    paymentStatus: "Paid",
    total: "$85",
  },
  {
    id: "3",
    orderId: "ORD-103",
    customer: "Carol",
    orderStatus: "Pending",
    paymentStatus: "Pending",
    total: "$200",
  },
  {
    id: "4",
    orderId: "ORD-104",
    customer: "Dave",
    orderStatus: "Delivered",
    paymentStatus: "Paid",
    total: "$56",
  },
  {
    id: "5",
    orderId: "ORD-105",
    customer: "Eve",
    orderStatus: "Processing",
    paymentStatus: "Failed",
    total: "$340",
  },
];

export function DataTable14({
  data = defaultData,
}: {
  data?: OrderFilterRow[];
}) {
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [globalFilter, setGlobalFilter] = React.useState("");
  const [orderStatusFilter, setOrderStatusFilter] =
    React.useState<string>("all");
  const [paymentFilter, setPaymentFilter] = React.useState<string>("all");

  const filteredData = React.useMemo(() => {
    return data.filter((row) => {
      if (orderStatusFilter !== "all" && row.orderStatus !== orderStatusFilter)
        return false;
      if (paymentFilter !== "all" && row.paymentStatus !== paymentFilter)
        return false;
      return true;
    });
  }, [data, orderStatusFilter, paymentFilter]);

  const columns: ColumnDef<OrderFilterRow>[] = React.useMemo(
    () => [
      { accessorKey: "orderId", header: "Order" },
      { accessorKey: "customer", header: "Customer" },
      {
        accessorKey: "orderStatus",
        header: "Order status",
        cell: ({ row }) => (
          <Badge variant="secondary">{row.original.orderStatus}</Badge>
        ),
      },
      {
        accessorKey: "paymentStatus",
        header: "Payment",
        cell: ({ row }) => (
          <Badge
            variant={
              row.original.paymentStatus === "Paid"
                ? "positive"
                : row.original.paymentStatus === "Failed"
                  ? "negative"
                  : "secondary"
            }
          >
            {row.original.paymentStatus}
          </Badge>
        ),
      },
      {
        accessorKey: "total",
        header: "Total",
        cell: ({ row }) => (
          <span className="tabular-nums">{row.original.total}</span>
        ),
      },
    ],
    [],
  );

  const table = useReactTable({
    data: filteredData,
    columns,
    state: { sorting, globalFilter },
    onSortingChange: setSorting,
    onGlobalFilterChange: setGlobalFilter,
    getCoreRowModel: getCoreRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getSortedRowModel: getSortedRowModel(),
  });

  const orderCounts = React.useMemo(() => {
    const counts: Record<string, number> = { all: data.length };
    data.forEach((r) => {
      counts[r.orderStatus] = (counts[r.orderStatus] ?? 0) + 1;
    });
    return counts;
  }, [data]);

  return (
    <div className="space-y-4 rounded-lg border border-border bg-background p-4">
      <div>
        <h2 className="text-lg font-semibold">Orders</h2>
        <p className="text-sm text-muted-foreground">
          Filter by order status, payment status, and search.
        </p>
      </div>
      <Tabs
        value={orderStatusFilter}
        onValueChange={setOrderStatusFilter}
        className="w-full"
      >
        <TabsList className="mb-2">
          <TabsTrigger value="all">All ({orderCounts.all})</TabsTrigger>
          <TabsTrigger value="Processing">
            Processing ({orderCounts.Processing ?? 0})
          </TabsTrigger>
          <TabsTrigger value="Shipped">
            Shipped ({orderCounts.Shipped ?? 0})
          </TabsTrigger>
          <TabsTrigger value="Pending">
            Pending ({orderCounts.Pending ?? 0})
          </TabsTrigger>
          <TabsTrigger value="Delivered">
            Delivered ({orderCounts.Delivered ?? 0})
          </TabsTrigger>
        </TabsList>
      </Tabs>
      <div className="flex flex-wrap gap-2">
        <Button
          variant={paymentFilter === "all" ? "secondary" : "primary"}
          size="sm"
          onClick={() => setPaymentFilter("all")}
        >
          All
        </Button>
        <Button
          variant={paymentFilter === "Paid" ? "secondary" : "primary"}
          size="sm"
          onClick={() => setPaymentFilter("Paid")}
        >
          Paid
        </Button>
        <Button
          variant={paymentFilter === "Pending" ? "secondary" : "primary"}
          size="sm"
          onClick={() => setPaymentFilter("Pending")}
        >
          Pending
        </Button>
        <Button
          variant={paymentFilter === "Failed" ? "secondary" : "primary"}
          size="sm"
          onClick={() => setPaymentFilter("Failed")}
        >
          Failed
        </Button>
        <Input
          placeholder="Search..."
          className="ml-auto h-8 w-[180px]"
          value={globalFilter}
          onChange={(e) => setGlobalFilter(e.target.value)}
        />
      </div>
      <div className="overflow-x-auto rounded-md border border-border">
        <Table>
          <TableHeader>
            {table
              .getHeaderGroups()
              .map((headerGroup: HeaderGroup<OrderFilterRow>) => (
                <TableRow key={headerGroup.id}>
                  {headerGroup.headers.map(
                    (header: Header<OrderFilterRow, unknown>) => {
                      const canSort = header.column.getCanSort();
                      const sorted = header.column.getIsSorted();
                      return (
                        <TableHead key={header.id}>
                          {canSort ? (
                            <Button
                              variant="primary"
                              size="sm"
                              className="-ml-3 h-8 gap-1"
                              onClick={() =>
                                header.column.toggleSorting(sorted === "asc")
                              }
                            >
                              {header.isPlaceholder
                                ? null
                                : flexRender(
                                    header.column.columnDef.header,
                                    header.getContext(),
                                  )}
                              {sorted === "desc" ? (
                                <ArrowDown className="size-4" />
                              ) : sorted === "asc" ? (
                                <ArrowUp className="size-4" />
                              ) : (
                                <ChevronsUpDown className="size-4 opacity-50" />
                              )}
                            </Button>
                          ) : header.isPlaceholder ? null : (
                            flexRender(
                              header.column.columnDef.header,
                              header.getContext(),
                            )
                          )}
                        </TableHead>
                      );
                    },
                  )}
                </TableRow>
              ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows.map((row: Row<OrderFilterRow>) => (
              <TableRow key={row.id}>
                {row
                  .getVisibleCells()
                  .map((cell: Cell<OrderFilterRow, unknown>) => (
                    <TableCell key={cell.id}>
                      {flexRender(
                        cell.column.columnDef.cell,
                        cell.getContext(),
                      )}
                    </TableCell>
                  ))}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>
      <div className="flex flex-wrap items-center justify-between gap-x-4 gap-y-2">
        <div className="flex min-w-0 flex-wrap items-center gap-x-2 gap-y-1 text-sm text-muted-foreground sm:flex-nowrap">
          <span className="whitespace-nowrap">Rows per page</span>
          <div className="w-20 shrink-0">
            <NativeSelect
              className="w-full min-w-0"
              value={String(table.getState().pagination.pageSize)}
              onChange={(e) => table.setPageSize(Number(e.target.value))}
            >
              <NativeSelectOption value="5">5</NativeSelectOption>
              <NativeSelectOption value="10">10</NativeSelectOption>
              <NativeSelectOption value="20">20</NativeSelectOption>
            </NativeSelect>
          </div>
          <span className="whitespace-nowrap">
            {table.getState().pagination.pageIndex *
              table.getState().pagination.pageSize +
              1}
            –
            {Math.min(
              (table.getState().pagination.pageIndex + 1) *
                table.getState().pagination.pageSize,
              table.getFilteredRowModel().rows.length,
            )}{" "}
            of {table.getFilteredRowModel().rows.length}
          </span>
        </div>
        <div className="flex shrink-0 gap-1">
          <Button
            variant="secondary"
            size="sm"
            onClick={() => table.previousPage()}
            disabled={!table.getCanPreviousPage()}
          >
            Previous
          </Button>
          <Button
            variant="secondary"
            size="sm"
            onClick={() => table.nextPage()}
            disabled={!table.getCanNextPage()}
          >
            Next
          </Button>
        </div>
      </div>
    </div>
  );
}

data-table16.source:
"use client";

import * as React from "react";
import {
  type ColumnDef,
  type Header,
  type HeaderGroup,
  type Row,
  type Cell,
  flexRender,
  getCoreRowModel,
  getExpandedRowModel,
  getSortedRowModel,
  useReactTable,
  type SortingState,
} from "@tanstack/react-table";
import {
  ArrowDown,
  ArrowUp,
  ChevronRight,
  ChevronsUpDown,
  MoreHorizontal,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";

export type OrderRow = {
  id: string;
  orderId: string;
  customer: string;
  total: string;
  status: string;
  shipping?: string;
  tracking?: string;
  warehouse?: string;
  assigned?: string;
};

const defaultData: OrderRow[] = [
  {
    id: "1",
    orderId: "ORD-001",
    customer: "Acme Corp",
    total: "$384.92",
    status: "Processing",
    shipping: "Express",
    tracking: "1Z999AA10123456784",
    warehouse: "WH-North",
    assigned: "Jane",
  },
  {
    id: "2",
    orderId: "ORD-002",
    customer: "Beta Inc",
    total: "$156.00",
    status: "Shipped",
    shipping: "Standard",
    tracking: "1Z999AA10987654321",
    warehouse: "WH-South",
    assigned: "John",
  },
  {
    id: "3",
    orderId: "ORD-003",
    customer: "Gamma LLC",
    total: "$892.50",
    status: "Pending",
    shipping: "Express",
    tracking: "-",
    warehouse: "WH-North",
    assigned: "Jane",
  },
];

export function DataTable16({ data = defaultData }: { data?: OrderRow[] }) {
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [rowSelection, setRowSelection] = React.useState({});
  const [expanded, setExpanded] = React.useState<Record<string, boolean>>({});

  const columns: ColumnDef<OrderRow>[] = React.useMemo(
    () => [
      {
        id: "expand",
        header: () => null,
        cell: ({ row }) => (
          <Button
            variant="primary"
            size="sm"
            className="h-8 w-8 p-0"
            onClick={() => row.toggleExpanded()}
            aria-label={row.getIsExpanded() ? "Collapse" : "Expand"}
          >
            <ChevronRight
              className={cn(
                "size-4 transition-transform",
                row.getIsExpanded() && "rotate-90",
              )}
            />
          </Button>
        ),
      },
      {
        id: "select",
        header: ({ table }) => (
          <Checkbox
            checked={table.getIsAllPageRowsSelected()}
            onCheckedChange={(v) => table.toggleAllPageRowsSelected(!!v)}
            aria-label="Select all"
          />
        ),
        cell: ({ row }) => (
          <Checkbox
            checked={row.getIsSelected()}
            onCheckedChange={(v) => row.toggleSelected(!!v)}
            aria-label="Select row"
          />
        ),
      },
      { accessorKey: "orderId", header: "Order" },
      { accessorKey: "customer", header: "Customer" },
      {
        accessorKey: "total",
        header: "Total",
        cell: ({ row }) => (
          <span className="tabular-nums font-medium">{row.original.total}</span>
        ),
      },
      {
        accessorKey: "status",
        header: "Status",
        cell: ({ row }) => (
          <Badge variant="secondary">{row.original.status}</Badge>
        ),
      },
      {
        id: "actions",
        cell: ({ row }) => (
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="primary" size="sm" className="h-8 w-8 p-0">
                <MoreHorizontal className="size-4" />
                <span className="sr-only">Actions</span>
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              <DropdownMenuItem>Edit</DropdownMenuItem>
              <DropdownMenuItem>View details</DropdownMenuItem>
              <DropdownMenuItem>Copy ID</DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        ),
      },
    ],
    [],
  );

  const table = useReactTable({
    data,
    columns,
    state: { sorting, rowSelection, expanded },
    onSortingChange: setSorting,
    onRowSelectionChange: setRowSelection,
    onExpandedChange: (value) => setExpanded(value as Record<string, boolean>),
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getExpandedRowModel: getExpandedRowModel(),
    getRowCanExpand: () => true,
  });

  return (
    <div className="space-y-4 rounded-lg border border-border bg-background p-4">
      <div>
        <h2 className="text-lg font-semibold">Orders</h2>
        <p className="text-sm text-muted-foreground">
          Expand a row to see shipping and assignment details.
        </p>
      </div>
      <div className="overflow-x-auto rounded-md border border-border">
        <Table>
          <TableHeader>
            {table
              .getHeaderGroups()
              .map((headerGroup: HeaderGroup<OrderRow>) => (
                <TableRow key={headerGroup.id}>
                  {headerGroup.headers.map(
                    (header: Header<OrderRow, unknown>) => {
                      const canSort = header.column.getCanSort();
                      const sorted = header.column.getIsSorted();
                      return (
                        <TableHead key={header.id}>
                          {canSort &&
                          header.id !== "expand" &&
                          header.id !== "select" &&
                          header.id !== "actions" ? (
                            <Button
                              variant="primary"
                              size="sm"
                              className="-ml-3 h-8 gap-1"
                              onClick={() =>
                                header.column.toggleSorting(sorted === "asc")
                              }
                            >
                              {header.isPlaceholder
                                ? null
                                : flexRender(
                                    header.column.columnDef.header,
                                    header.getContext(),
                                  )}
                              {sorted === "desc" ? (
                                <ArrowDown className="size-4" />
                              ) : sorted === "asc" ? (
                                <ArrowUp className="size-4" />
                              ) : (
                                <ChevronsUpDown className="size-4 opacity-50" />
                              )}
                            </Button>
                          ) : header.isPlaceholder ? null : (
                            flexRender(
                              header.column.columnDef.header,
                              header.getContext(),
                            )
                          )}
                        </TableHead>
                      );
                    },
                  )}
                </TableRow>
              ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows.map((row: Row<OrderRow>) => (
              <React.Fragment key={row.id}>
                <TableRow data-state={row.getIsSelected() && "selected"}>
                  {row
                    .getVisibleCells()
                    .map((cell: Cell<OrderRow, unknown>) => (
                      <TableCell key={cell.id}>
                        {flexRender(
                          cell.column.columnDef.cell,
                          cell.getContext(),
                        )}
                      </TableCell>
                    ))}
                </TableRow>
                {row.getIsExpanded() && row.original.shipping != null && (
                  <TableRow className="bg-muted/30 hover:bg-muted/30">
                    <TableCell colSpan={columns.length} className="py-3">
                      <div className="grid gap-2 rounded-md bg-muted/50 p-4 text-sm sm:grid-cols-2 md:grid-cols-4">
                        <div>
                          <span className="text-muted-foreground">
                            Shipping
                          </span>{" "}
                          {row.original.shipping}
                        </div>
                        <div>
                          <span className="text-muted-foreground">
                            Tracking
                          </span>{" "}
                          {row.original.tracking}
                        </div>
                        <div>
                          <span className="text-muted-foreground">
                            Warehouse
                          </span>{" "}
                          {row.original.warehouse}
                        </div>
                        <div>
                          <span className="text-muted-foreground">
                            Assigned
                          </span>{" "}
                          {row.original.assigned}
                        </div>
                      </div>
                    </TableCell>
                  </TableRow>
                )}
              </React.Fragment>
            ))}
          </TableBody>
        </Table>
      </div>
    </div>
  );
}

data-table20.source:
"use client";

import * as React from "react";
import {
  type ColumnDef,
  type Header,
  type HeaderGroup,
  type Row,
  type Cell,
  flexRender,
  getCoreRowModel,
  getSortedRowModel,
  useReactTable,
  type SortingState,
  type ColumnSizingState,
} from "@tanstack/react-table";
import { ArrowDown, ArrowUp, ChevronsUpDown } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";

const defaultColumnSizing: ColumnSizingState = {
  sku: 100,
  name: 180,
  type: 90,
  stock: 90,
  availability: 110,
};

export type ResizeRow = {
  id: string;
  sku: string;
  name: string;
  type: string;
  stock: string;
  availability: string;
};

const defaultData: ResizeRow[] = [
  {
    id: "1",
    sku: "SKU-001",
    name: "Widget A",
    type: "Product",
    stock: "In stock",
    availability: "Available",
  },
  {
    id: "2",
    sku: "SKU-002",
    name: "Widget B",
    type: "Product",
    stock: "Low",
    availability: "Limited",
  },
  {
    id: "3",
    sku: "SKU-003",
    name: "Service Pack",
    type: "Service",
    stock: "In stock",
    availability: "Available",
  },
];

export function DataTable20({ data = defaultData }: { data?: ResizeRow[] }) {
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [columnSizing, setColumnSizing] =
    React.useState<ColumnSizingState>(defaultColumnSizing);
  const [resizingCol, setResizingCol] = React.useState<string | null>(null);

  const columns: ColumnDef<ResizeRow>[] = React.useMemo(
    () => [
      {
        accessorKey: "sku",
        header: "SKU",
        size: 100,
        minSize: 60,
        cell: ({ row }) => (
          <span className="font-mono text-xs uppercase">
            {row.original.sku}
          </span>
        ),
      },
      { accessorKey: "name", header: "Item name", size: 180, minSize: 80 },
      { accessorKey: "type", header: "Type", size: 90, minSize: 60 },
      { accessorKey: "stock", header: "Stock", size: 90, minSize: 60 },
      {
        accessorKey: "availability",
        header: "Availability",
        size: 110,
        minSize: 80,
        cell: ({ row }) => (
          <Badge variant="secondary">{row.original.availability}</Badge>
        ),
      },
    ],
    [],
  );

  const table = useReactTable({
    data,
    columns,
    state: { sorting, columnSizing },
    onSortingChange: setSorting,
    onColumnSizingChange: setColumnSizing,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    columnResizeMode: "onChange",
  });

  const startResize = (columnId: string, clientX: number) => {
    setResizingCol(columnId);
    const col = table.getColumn(columnId);
    const startW = col ? col.getSize() : 100;
    const startX = clientX;
    const onMove = (e: MouseEvent) => {
      const delta = e.clientX - startX;
      setColumnSizing((p) => ({
        ...p,
        [columnId]: Math.max(60, startW + delta),
      }));
    };
    const onUp = () => {
      setResizingCol(null);
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseup", onUp);
    };
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
  };

  return (
    <div className="space-y-4 rounded-lg border border-border bg-background p-4">
      <div>
        <h2 className="text-lg font-semibold">Resizable columns</h2>
        <p className="text-sm text-muted-foreground">
          Drag the handle on the right of a header to resize.
        </p>
      </div>
      <div className="overflow-x-auto rounded-md border border-border">
        <Table>
          <TableHeader>
            {table
              .getHeaderGroups()
              .map((headerGroup: HeaderGroup<ResizeRow>) => (
                <TableRow key={headerGroup.id}>
                  {headerGroup.headers.map(
                    (header: Header<ResizeRow, unknown>) => {
                      const colId = header.column.id;
                      const width = header.column.getSize();
                      const canSort = header.column.getCanSort();
                      const sorted = header.column.getIsSorted();
                      return (
                        <TableHead
                          key={header.id}
                          style={{ width, minWidth: width, maxWidth: width }}
                          className="relative"
                        >
                          <div className="flex items-center gap-1">
                            {canSort ? (
                              <Button
                                variant="primary"
                                size="sm"
                                className="-ml-3 h-8 gap-1"
                                onClick={() =>
                                  header.column.toggleSorting(sorted === "asc")
                                }
                              >
                                {header.isPlaceholder
                                  ? null
                                  : flexRender(
                                      header.column.columnDef.header,
                                      header.getContext(),
                                    )}
                                {sorted === "desc" ? (
                                  <ArrowDown className="size-4" />
                                ) : sorted === "asc" ? (
                                  <ArrowUp className="size-4" />
                                ) : (
                                  <ChevronsUpDown className="size-4 opacity-50" />
                                )}
                              </Button>
                            ) : header.isPlaceholder ? null : (
                              flexRender(
                                header.column.columnDef.header,
                                header.getContext(),
                              )
                            )}
                          </div>
                          <div
                            role="separator"
                            className={cn(
                              "absolute right-0 top-0 h-full w-1 cursor-col-resize touch-none select-none bg-transparent hover:bg-brand/30",
                              resizingCol === colId && "bg-brand/50",
                            )}
                            onMouseDown={(e) => startResize(colId, e.clientX)}
                            aria-label={`Resize ${colId}`}
                          />
                        </TableHead>
                      );
                    },
                  )}
                </TableRow>
              ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows.map((row: Row<ResizeRow>) => (
              <TableRow key={row.id}>
                {row.getVisibleCells().map((cell: Cell<ResizeRow, unknown>) => {
                  const w = cell.column.getSize();
                  return (
                    <TableCell
                      key={cell.id}
                      style={{ width: w, minWidth: w, maxWidth: w }}
                    >
                      {flexRender(
                        cell.column.columnDef.cell,
                        cell.getContext(),
                      )}
                    </TableCell>
                  );
                })}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>
    </div>
  );
}

