                    key={headerGroup.id}
                    className="border-0! hover:bg-transparent"
                  >
                    {headerGroup.headers.map((header) => {
                      const meta =
                        (header.column.columnDef.meta as ColumnMeta) ?? {};
                      const sizeStyle: React.CSSProperties = {};
                      if (meta.width !== undefined) {
                        sizeStyle.width =
                          typeof meta.width === "number"
                            ? `${meta.width}px`
                            : meta.width;
                      }
                      if (meta.minWidth !== undefined) {
                        sizeStyle.minWidth =
                          typeof meta.minWidth === "number"
                            ? `${meta.minWidth}px`
                            : meta.minWidth;
                      }
                      if (meta.maxWidth !== undefined) {
                        sizeStyle.maxWidth =
                          typeof meta.maxWidth === "number"
                            ? `${meta.maxWidth}px`
                            : meta.maxWidth;
                      }
                      const baseClassName = cn(
                        "relative !h-11 border-r-[0.5px] border-border/60 bg-[var(--dt-header-bg)] !px-3 text-left align-middle !text-[0.8125rem] font-medium !text-muted-foreground whitespace-nowrap last:border-r-0",
                        header.column.id === rightStickyDividerTargetId &&
                          "!border-r-0",
                        meta.headerClassName,
                      );

                      const stickyStyle =
                        header.column.id === "actions"
                          ? undefined
                          : getStickyStyle(header.column.id);
                      const isLeftSticky = isLeftStickyColumn(header.column.id);
                      const isRightSticky = isRightStickyColumn(
                        header.column.id,
                      );
                      const headerContent = header.isPlaceholder ? null : header
                          .column.id === "description" ? (
                        <div className="flex items-center justify-between gap-2">
                          {flexRender(
                            header.column.columnDef.header,
                            header.getContext(),
                          )}
                          <HorizontalPagination
                            canScrollLeft={tableScroll.canScrollLeft}
                            canScrollRight={tableScroll.canScrollRight}
                            onScrollLeft={tableScroll.scrollLeft}
                            onScrollRight={tableScroll.scrollRight}
                            className="hidden md:flex"
                          />
                        </div>
                      ) : (
                        flexRender(
                          header.column.columnDef.header,
                          header.getContext(),
                        )
                      );

                      return (
                        <TableHead
                          key={header.id}
                          colSpan={header.colSpan}
                          className={getStickyClassName(
                            header.column.id,
                            baseClassName,
                            true,
                          )}
                          style={{ ...sizeStyle, ...(stickyStyle ?? {}) }}
                        >
                          {isLeftSticky || isRightSticky ? (
                            <div
                              className={cn(
                                "sticky top-0 flex h-full min-h-11 items-center bg-[var(--dt-header-bg)] px-3",
                                isLeftSticky &&
                                  "left-[var(--stick-left)] z-30 shadow-[2px_0_4px_-2px_rgba(0,0,0,0.1)] dark:shadow-[2px_0_4px_-2px_rgba(0,0,0,0.3)]",
                                isRightSticky &&
                                  "right-0 z-30 shadow-[-2px_0_4px_-2px_rgba(0,0,0,0.1)] dark:shadow-[-2px_0_4px_-2px_rgba(0,0,0,0.3)]",
                              )}
                              style={
                                isLeftSticky && stickyStyle
                                  ? { ...stickyStyle, ...sizeStyle }
                                  : isRightSticky
                                    ? { ...sizeStyle }
                                    : undefined
                              }
                            >
                              {headerContent}
                            </div>
                          ) : (
                            headerContent
                          )}
                        </TableHead>
                      );
                    })}
                  </TableRow>
                ))}
              </TableHeader>
              <TableBody>
                {table.getRowModel().rows?.length ? (
                  table.getRowModel().rows.map((row) => (
                    <TableRow
                      key={row.id}
                      data-state={row.getIsSelected() && "selected"}
                      className="group h-11 !border-b-[0.5px] border-border/60 bg-[var(--dt-row-bg)] [--dt-row-bg:var(--dt-cell-bg)] transition-colors hover:[--dt-row-bg:var(--dt-row-hover-bg)] data-[state=selected]:[--dt-row-bg:var(--dt-row-selected-bg)] data-[state=selected]:hover:[--dt-row-bg:var(--dt-row-selected-hover-bg)] last:border-b-0"
                    >
                      {row.getVisibleCells().map((cell) => {
                        const meta =
                          (cell.column.columnDef.meta as ColumnMeta) ?? {};
                        const sizeStyle: React.CSSProperties = {};
                        if (meta.width !== undefined) {
                          sizeStyle.width =
                            typeof meta.width === "number"
                              ? `${meta.width}px`
                              : meta.width;
                        }
                        if (meta.minWidth !== undefined) {
                          sizeStyle.minWidth =
                            typeof meta.minWidth === "number"
                              ? `${meta.minWidth}px`
                              : meta.minWidth;
                        }
                        if (meta.maxWidth !== undefined) {
                          sizeStyle.maxWidth =
                            typeof meta.maxWidth === "number"
                              ? `${meta.maxWidth}px`
                              : meta.maxWidth;
                        }
                        const baseClassName = cn(
                          "relative h-11 border-r-[0.5px] border-border/60 bg-[var(--dt-row-bg)] !px-3 !py-2 align-middle !text-[0.8125rem] text-foreground whitespace-nowrap last:border-r-0",
                          cell.column.id === rightStickyDividerTargetId &&
                            "!border-r-0",
                          meta.cellClassName,
                        );

                        const stickyStyle =
                          cell.column.id === "actions"
                            ? undefined
                            : getStickyStyle(cell.column.id);
                        const isLeftSticky = isLeftStickyColumn(cell.column.id);
                        const isRightSticky = isRightStickyColumn(
                          cell.column.id,
                        );
                        const cellContent = flexRender(
                          cell.column.columnDef.cell,
                          cell.getContext(),
                        );

                        return (
                          <TableCell
                            key={cell.id}
                            className={getStickyClassName(
                              cell.column.id,
                              baseClassName,
                              false,
                            )}
                            style={{ ...sizeStyle, ...(stickyStyle ?? {}) }}
                          >
                            {isLeftSticky || isRightSticky ? (
                              <div
                                className={cn(
                                  "sticky flex h-full min-h-[2.25rem] items-center bg-[var(--dt-row-bg)] px-3",
                                  isLeftSticky &&
                                    "left-[var(--stick-left)] z-20 shadow-[2px_0_4px_-2px_rgba(0,0,0,0.1)] dark:shadow-[2px_0_4px_-2px_rgba(0,0,0,0.3)]",
                                  isRightSticky &&
                                    "right-0 z-20 shadow-[-2px_0_4px_-2px_rgba(0,0,0,0.1)] dark:shadow-[-2px_0_4px_-2px_rgba(0,0,0,0.3)]",
                                )}
                                style={
                                  isLeftSticky && stickyStyle
                                    ? { ...stickyStyle, ...sizeStyle }
                                    : isRightSticky
                                      ? { ...sizeStyle }
                                      : undefined
                                }
                              >
                                {cellContent}
                              </div>
                            ) : (
                              cellContent
                            )}
                          </TableCell>
                        );
                      })}
                    </TableRow>
                  ))
                ) : (
                  <TableRow>
                    <TableCell
                      colSpan={visibleColumnCount}
                      className="h-24 text-center text-[0.8125rem] text-muted-foreground"
                    >
                      No transactions.
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </table>
          </div>
        </div>
      </div>
    </section>
  );
};

