import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";

export function Login4({
  logo,
  title = "Log in",
  onGoogle,
  onFacebook,
  onGitHub,
  onSubmit,
  rememberMeDefault = false,
  signUpHref = "#",
  forgotPasswordHref = "#",
  className,
}: {
  logo?: React.ReactNode;
  title?: string;
  onGoogle?: () => void;
  onFacebook?: () => void;
  onGitHub?: () => void;
  onSubmit?: (email: string, password: string, rememberMe: boolean) => void;
  rememberMeDefault?: boolean;
  signUpHref?: string;
  forgotPasswordHref?: string;
  className?: string;
}) {
  const [email, setEmail] = React.useState("");
  const [password, setPassword] = React.useState("");
  const [rememberMe, setRememberMe] = React.useState(rememberMeDefault);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit?.(email, password, rememberMe);
  };

  const hasSocial = onGoogle || onFacebook || onGitHub;

  return (
    <div
      className={cn(
        "flex w-full max-w-sm flex-col gap-6 rounded-lg border border-border bg-background p-6",
        className,
      )}
    >
      {logo && <div className="flex justify-center">{logo}</div>}
      <div className="space-y-1 text-center">
        <h2 className="text-xl font-semibold">{title}</h2>
        <p className="text-sm text-muted-foreground">
          Enter your credentials or use a provider.
        </p>
      </div>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="space-y-2">
          <label
            htmlFor="login4-email"
            className="text-sm font-medium leading-none"
          >
            Email
          </label>
          <Input
            id="login4-email"
            type="email"
            placeholder="you@example.com"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="w-full"
          />
        </div>
        <div className="space-y-2">
          <label
            htmlFor="login4-password"
            className="text-sm font-medium leading-none"
          >
            Password
          </label>
          <Input
            id="login4-password"
            type="password"
            placeholder="••••••••"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full"
          />
        </div>
        <div className="flex items-center justify-between gap-2">
          <label className="flex cursor-pointer items-center gap-2 text-sm">
            <Checkbox
              checked={rememberMe}
              onCheckedChange={(v) => setRememberMe(v === true)}
              aria-label="Remember me"
            />
