        </>
      )}
      <p className="text-center text-sm text-muted-foreground">
        Don&apos;t have an account?{" "}
        <a
          href={signUpHref}
          className="underline underline-offset-2 hover:text-foreground"
        >
          Sign up
        </a>
      </p>
    </div>
  );
}

