    { label: "GitHub", href: "#" },
    { label: "Discord", href: "#" },
    { label: "LinkedIn", href: "#" },
    { label: "YouTube", href: "#" },
    { label: "Newsletter", href: "#" },
  ],
];

const MOBILE_NAV_ITEMS = [
  { label: "Home", href: "#" },
  { label: "About", href: "#" },
  { label: "Services", href: "#" },
  { label: "Portfolio", href: "#" },
  { label: "Blog", href: "#" },
  { label: "Contact", href: "#" },
  { label: "Sign In", href: "#" },
  { label: "Pricing", href: "#" },
  { label: "Contact", href: "#" },
];

const FOOTER_LINKS = [
  { label: "Privacy Policy", href: "#" },
  { label: "Terms of Service", href: "#" },
];

const COMPANY_LINKS = [
  { label: "+1 (234) 234-00000", href: "#" },
  { label: "2026© blakeui.com", href: "#" },
];

interface Navbar29Props {
  className?: string;
}

const Navbar29 = ({ className }: Navbar29Props) => {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <section className={cn("", className)}>
      <nav className="relative">
        <ul className="relative z-1 flex w-full list-none items-center justify-between gap-4 p-6 text-lg font-semibold tracking-tight">
          <li className="w-35">BlakeUI</li>
          {NAV_ITEMS.map((item, index) => (
            <li key={index} className="hidden w-32 lg:block">
              <a
                href={item.href}
                className="no-underline transition-colors hover:text-foreground/70"
              >
                {item.label}
              </a>
            </li>
          ))}
          <li className="lg:w-14 ">
            <Menu setIsOpen={setIsOpen} isOpen={isOpen} />
          </li>
        </ul>

        <AnimatePresence mode="popLayout">
          {isOpen && (
            <motion.div
              className="absolute top-0 w-full bg-muted px-6 pt-30 pb-10"
              initial={{ clipPath: "inset(0 0 100% 0)" }}
              animate={{ clipPath: "inset(0% 0 0 0)" }}
              exit={{ clipPath: "inset(0 0 100% 0)" }}
              transition={{
                duration: 0.35,
                ease: [0.4, 0.0, 0.2, 1],
              }}
            >
              <div className="flex lg:hidden">
                <ul className="flex flex-col gap-5 text-2xl font-semibold tracking-tight">
                  {MOBILE_NAV_ITEMS.map((item, index) => (
                    <li key={index}>{item.label}</li>
                  ))}
                </ul>
              </div>
              <div className="hidden w-full items-center justify-between gap-4 lg:flex">
                <div className="w-35 opacity-0">BlakeUI</div>
                {MEGA_MENU_ITEMS.map((section, sectionIndex) => (
                  <ul key={sectionIndex} className="space-y-5">
                    {section.map((item, itemIndex) => (
                      <li key={itemIndex} className="w-32 list-none">
                        <a
                          href={item.href}
                          className="group/menu-item flex w-full items-center gap-1 text-foreground/40 no-underline hover:text-foreground"
                        >
                          <span>{item.label}</span>
                          <ArrowUpRight
                            aria-hidden
                            className="size-4 shrink-0 translate-y-0.5 opacity-0 transition-all ease-out group-hover/menu-item:translate-y-0 group-hover/menu-item:opacity-100"
                          />
                        </a>
                      </li>
                    ))}
                  </ul>
                ))}
                <div className="w-14" />
              </div>
              <div className="mt-40 flex w-full flex-col items-center justify-between gap-2 text-sm lg:flex-row lg:gap-4 lg:text-base">
                <div className="flex items-center gap-4 lg:gap-10">
                  {COMPANY_LINKS.map((item, index) => (
                    <p key={index}>{item.label}</p>
                  ))}
                </div>
                <div className="flex items-center gap-4 lg:gap-10">
                  {FOOTER_LINKS.map((item, index) => (
                    <p key={index}>{item.label}</p>
                  ))}
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </nav>
    </section>
  );
};

export { Navbar29 };

const Menu = ({
  className,
  setIsOpen,
  isOpen,
}: {
  className?: string;
  setIsOpen: (value: boolean | ((prev: boolean) => boolean)) => void;
  isOpen: boolean;
}) => {
  return (
    <button
      className={cn(
        "relative flex h-2 w-8 flex-col items-center justify-center gap-2 after:absolute after:h-12 after:w-full lg:w-14",
        className,
      )}
      onClick={() => setIsOpen((x: boolean) => !x)}
    >
      <motion.div
        animate={{ y: isOpen ? 0 : 5, rotate: isOpen ? 45 : 0 }}
        className="absolute h-0.5 w-full bg-foreground"
      />
      <motion.div
        animate={{ y: isOpen ? 0 : -5, rotate: isOpen ? -45 : 0 }}
        className="absolute h-0.5 w-full bg-foreground"
      />
    </button>
  );
};

navbar-9.source:
"use client";

import type { LucideIcon } from "lucide-react";
import {
  Bell,
  Book,
  ChevronRight,
  FileText,
  Globe,
  Grid,
  HelpCircle,
  Info,
  Menu,
  X,
} from "lucide-react";
import { Fragment, useEffect, useState } from "react";

import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion";
import { Button } from "@/components/ui/button";
import {
  NavigationMenu,
  NavigationMenuContent,
  NavigationMenuItem,
  NavigationMenuLink,
  NavigationMenuList,
  NavigationMenuTrigger,
  navigationMenuTriggerStyle,
} from "@/components/ui/navigation-menu";
import { Sheet, SheetContent, SheetTitle } from "@/components/ui/sheet";
import { cn } from "@/lib/utils";
import { AppLink } from "./link";
import { BlakeLogoIcon } from "../blake-logo-icon";

interface MenuLink {
  label: string;
  description?: string;
  url?: string;
  icon?: {
    component: LucideIcon;
    color: string;
  };
}
interface MenuItem {
  title: string;
  url?: string;
  links?: MenuLink[];
}

interface DesktopMenuItemProps {
  item: MenuItem;
  index: number;
}

interface MobileNavigationMenuProps {
  open: boolean;
}

interface MenuSubLinkProps {
  link: MenuLink;
}

const NAVIGATION: MenuItem[] = [
  {
    title: "Products",
    links: [
      {
        label: "Company Blog",
        description: "Insights & updates",
        url: "#",
        icon: {
          component: FileText,
          color: "#10b981",
        },
      },
      {
        label: "Our Platform",
        description: "Empower your work",
        url: "#",
        icon: {
          component: Grid,
          color: "#6366f1",
        },
      },
    ],
  },
  {
    title: "Company",
    links: [
      {
        label: "About Our Team",
        url: "#",
        description: "Our mission & values",
        icon: {
          component: Info,
          color: "#f59e0b",
        },
      },
      {
        label: "Help & Support Center",
        url: "#",
        description: "Get quick help",
        icon: {
          component: HelpCircle,
          color: "#3b82f6",
        },
      },
      {
        label: "Latest News",
        url: "#",
        description: "Product updates",
        icon: {
          component: Bell,
          color: "#f97316",
        },
      },
    ],
  },
  {
    title: "Resources",
    links: [
      {
        label: "Documentation",
        url: "#",
        description: "Guides & references",
        icon: {
          component: Book,
          color: "#8b5cf6",
        },
      },
      {
        label: "API Reference",
        url: "#",
        description: "Explore our API",
        icon: {
          component: Globe,
          color: "#ef4444",
        },
      },
    ],
  },
  {
    title: "Pricing",
    url: "#",
  },
  {
    title: "Contact",
    url: "#",
  },
];

const PRIMARY_BUTTON = {
  label: "Sign up",
  url: "#",
};

const MOBILE_BREAKPOINT = 1024;

interface Navbar9Props {
  className?: string;
}

const Navbar9 = ({ className }: Navbar9Props) => {
  const [open, setOpen] = useState<boolean>(false);

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth > MOBILE_BREAKPOINT) {
        setOpen(false);
      }
    };

    handleResize();

    window.addEventListener("resize", handleResize);
    return () => {
      window.removeEventListener("resize", handleResize);
    };
  }, []);

  useEffect(() => {
    document.body.style.overflow = open ? "hidden" : "auto";
  }, [open]);

  const handleMobileMenu = () => {
    const nextOpen = !open;
    setOpen(nextOpen);
  };

  return (
    <Fragment>
      <section
        className={cn("pointer-events-auto relative bg-brand", className)}
      >
        <div className="container mx-auto h-16 px-2">
          <div className="flex h-full items-center justify-between">
            <a
              href="#"
              className="flex max-h-8 items-center gap-2 text-lg font-semibold tracking-tighter no-underline"
            >
              <BlakeLogoIcon className="size-8" />
              <span className="hidden text-background md:inline-block">
                BlakeUI
              </span>
            </a>
            <NavigationMenu className="hidden lg:flex" viewport={false}>
              <NavigationMenuList className="">
                {NAVIGATION.map((item, index) => (
                  <DesktopMenuItem
                    key={`desktop-link-${index}`}
                    item={item}
                    index={index}
                  />
                ))}
              </NavigationMenuList>
            </NavigationMenu>
            <div className="flex items-center gap-4">
              <GithubStars repoUrl="https://github.com/shadcn/ui" />
              <Button asChild>
                <AppLink href={PRIMARY_BUTTON.url}>
                  {PRIMARY_BUTTON.label}
                </AppLink>
              </Button>
              <div className="lg:hidden">
                <Button variant="primary" size="sm" onClick={handleMobileMenu}>
                  {open ? (
                    <X className="size-5.5 stroke-foreground" />
                  ) : (
                    <Menu className="size-5.5 stroke-foreground" />
                  )}
                </Button>
              </div>
            </div>
          </div>
        </div>
      </section>
      <MobileNavigationMenu open={open} />
    </Fragment>
  );
};

const DesktopMenuItem = ({ item, index }: DesktopMenuItemProps) => {
  if (item.links) {
    return (
      <NavigationMenuItem key={`desktop-menu-item-${index}`} value={`${index}`}>
        <NavigationMenuTrigger className="h-fit bg-transparent font-normal text-background no-underline focus:bg-transparent! data-[active=true]:bg-transparent!">
          {item.title}
        </NavigationMenuTrigger>
        <NavigationMenuContent className="rounded-xl! p-0!">
          <ul className="w-[20rem] p-2.5">
            {item.links.map((link, index) => (
              <li key={`desktop-nav-sublink-${index}`}>
                <MenuSubLink link={link} />
              </li>
            ))}
          </ul>
        </NavigationMenuContent>
      </NavigationMenuItem>
    );
  }

  return (
    <NavigationMenuItem key={`desktop-menu-item-${index}`} value={`${index}`}>
      <NavigationMenuLink
        href={item.url}
        className={`${navigationMenuTriggerStyle()} h-fit bg-transparent font-normal text-background no-underline`}
      >
        {item.title}
      </NavigationMenuLink>
    </NavigationMenuItem>
  );
};

const MenuSubLink = ({ link }: MenuSubLinkProps) => {
  return (
    <a
      href={link.url}
      className="flex items-center gap-4 rounded-lg p-2 no-underline hover:bg-muted"
    >
      <div className="flex w-full items-center justify-between">
        <div className="flex gap-2.5">
          {link.icon && (
            <link.icon.component
              className="size-5"
              style={{ stroke: link.icon.color }}
            />
          )}
          <div className="flex flex-col gap-1.5">
            <h3 className="text-sm leading-none text-background">
              {link.label}
            </h3>
            <p className="text-sm leading-[1.2] text-background/80">
              {link.description}
            </p>
          </div>
        </div>
        <ChevronRight className="size-3.5 stroke-muted-foreground opacity-100" />
      </div>
    </a>
  );
};

const MobileNavigationMenu = ({ open }: MobileNavigationMenuProps) => {
  return (
    <Sheet open={open}>
      <SheetContent
        aria-describedby={undefined}
        side="top"
        className="inset-0 z-998 h-dvh w-full bg-brand pt-16 [&>button]:hidden"
      >
        <div className="flex-1 overflow-y-auto">
          <div className="container pb-12">
            <div className="absolute -m-px h-px w-px overflow-hidden border-0 mask-clip-border p-0 text-nowrap whitespace-nowrap">
              <SheetTitle className="text-primary">
                Mobile Navigation
              </SheetTitle>
            </div>
            <div className="flex h-full flex-col justify-between gap-20">
              <Accordion type="multiple" className="w-full">
                {NAVIGATION.map((item, index) =>
                  renderMobileMenuItem(item, index),
                )}
              </Accordion>
              <div className="pb-20">
                <Button asChild className="w-full">
                  <a href={PRIMARY_BUTTON.url} className="no-underline">
                    {PRIMARY_BUTTON.label}
                  </a>
                </Button>
              </div>
            </div>
          </div>
        </div>
      </SheetContent>
    </Sheet>
  );
};

const renderMobileMenuItem = (item: MenuItem, index: number) => {
  if (item.links) {
    return (
      <AccordionItem key={item.title} value={`nav-${index}`}>
        <AccordionTrigger className="h-15 items-center p-0 text-base leading-[3.75] font-normal text-background hover:no-underline">
          {item.title}
        </AccordionTrigger>
        <AccordionContent>
          {item.links.map((subItem) => (
            <MenuSubLink key={subItem.label} link={subItem} />
          ))}
        </AccordionContent>
      </AccordionItem>
    );
  }

  return (
    <a
      key={item.title}
      href={item.url}
      className="flex h-15 items-center border-b p-0 text-left text-base leading-[3.75] font-normal text-background ring-ring/10 outline-ring/50 transition-all no-underline focus-visible:ring-4 focus-visible:outline-1 nth-last-1:border-0"
    >
      {item.title}
    </a>
  );
};

interface GithubStarsProps {
  repoUrl: string;
}

const GithubStars = ({ repoUrl }: GithubStarsProps) => {
  const [stargazersCount, setStargazersCount] = useState<string>("");

  const [owner, repo] = repoUrl.split("github.com/")[1].split("/");
  const githubApiEndpoint = `https://api.github.com/repos/${owner}/${repo}`;

  const formatStargazers = (count: number | ""): string => {
    if (count === "") return "";
    if (count < 1000) return count.toString();
    return `${Math.round(count / 1000)}k`;
  };

  useEffect(() => {
    const getStars = async () => {
      try {
        const response = await fetch(githubApiEndpoint);
        const json = await response.json();
        const formattedCount = formatStargazers(json.stargazers_count);
        setStargazersCount(formattedCount);
      } catch (error: unknown) {
        if (error instanceof Error) {
          console.error(error.message);
        }
      }
    };

    getStars();
  }, [githubApiEndpoint]);

