settings-profile-6.source:
"use client";

import * as React from "react";
import { z } from "zod";
import { Check } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { cn } from "@/lib/utils";

const steps = [
  { id: "basic", title: "Basic Info", description: "Name and bio" },
  { id: "contact", title: "Contact", description: "Email and phone" },
  { id: "social", title: "Social", description: "Links" },
  { id: "review", title: "Review", description: "Confirm" },
];

const basicSchema = z.object({
  name: z.string().min(1, "Name is required"),
  username: z.string().min(2, "Username must be at least 2 characters").regex(/^[a-z0-9_-]+$/i, "Username can only contain letters, numbers, underscore and hyphen"),
  bio: z.string().optional(),
});

const contactSchema = z.object({
  email: z.string().min(1, "Email is required").email("Enter a valid email"),
  phone: z.string().optional(),
});

const socialSchema = z.object({
  website: z.union([z.string().url("Enter a valid URL"), z.literal("")]).optional(),
});

export function SettingsProfile6() {
  const [step, setStep] = React.useState(0);
  const [data, setData] = React.useState({
    name: "",
    username: "",
    bio: "",
    email: "",
    phone: "",
    website: "",
  });
  const [errors, setErrors] = React.useState<Record<string, string>>({});

  const currentStepId = steps[step].id;
  const isLast = step === steps.length - 1;

  const validateStep = (): boolean => {
    if (currentStepId === "basic") {
      const result = basicSchema.safeParse({ name: data.name, username: data.username, bio: data.bio });
      if (!result.success) {
        const fieldErrors: Record<string, string> = {};
        result.error.issues.forEach((issue) => {
          const path = String(issue.path[0]);
          if (path && !fieldErrors[path]) fieldErrors[path] = issue.message;
        });
        setErrors(fieldErrors);
        return false;
      }
    } else if (currentStepId === "contact") {
      const result = contactSchema.safeParse({ email: data.email, phone: data.phone });
      if (!result.success) {
        const fieldErrors: Record<string, string> = {};
        result.error.issues.forEach((issue) => {
          const path = String(issue.path[0]);
          if (path && !fieldErrors[path]) fieldErrors[path] = issue.message;
        });
        setErrors(fieldErrors);
        return false;
      }
    } else if (currentStepId === "social") {
      const result = socialSchema.safeParse({ website: data.website });
      if (!result.success) {
        const fieldErrors: Record<string, string> = {};
        result.error.issues.forEach((issue) => {
          const path = String(issue.path[0]);
          if (path && !fieldErrors[path]) fieldErrors[path] = issue.message;
        });
        setErrors(fieldErrors);
        return false;
      }
    }
    setErrors({});
    return true;
  };

  const goNext = () => {
    if (isLast) {
      const allResult = basicSchema.safeParse({ name: data.name, username: data.username, bio: data.bio });
      const contactResult = contactSchema.safeParse({ email: data.email, phone: data.phone });
      const socialResult = socialSchema.safeParse({ website: data.website });
      const fieldErrors: Record<string, string> = {};
      if (!allResult.success) allResult.error.issues.forEach((issue) => { const p = String(issue.path[0]); if (p && !fieldErrors[p]) fieldErrors[p] = issue.message; });
      if (!contactResult.success) contactResult.error.issues.forEach((issue) => { const p = String(issue.path[0]); if (p && !fieldErrors[p]) fieldErrors[p] = issue.message; });
      if (!socialResult.success) socialResult.error.issues.forEach((issue) => { const p = String(issue.path[0]); if (p && !fieldErrors[p]) fieldErrors[p] = issue.message; });
      if (Object.keys(fieldErrors).length > 0) { setErrors(fieldErrors); return; }
      setErrors({});
      return;
    }
    if (!validateStep()) return;
    setStep((s) => Math.min(steps.length - 1, s + 1));
  };

  return (
    <div className="mx-auto max-w-xl w-full rounded-lg border border-border bg-background p-6">
      <div className="mb-8 flex items-center justify-between gap-2">
        {steps.map((s, i) => (
          <React.Fragment key={s.id}>
            <div className="flex flex-col items-center">
              <div
                className={cn(
                  "flex size-8 items-center justify-center rounded-full border text-sm font-medium",
                  i < step && "border-brand bg-brand text-white",
                  i === step && "border-brand bg-background text-foreground",
                  i > step && "border-border text-muted-foreground",
                )}
              >
                {i < step ? <Check className="size-4" /> : i + 1}
              </div>
              <p className="mt-2 text-xs mb-0! font-medium">{s.title}</p>
              <p className="text-[10px] my-0! text-muted-foreground">
                {s.description}
              </p>
            </div>
            {i < steps.length - 1 && (
              <div className="h-px flex-1 bg-border" aria-hidden />
            )}
          </React.Fragment>
        ))}
      </div>

      {currentStepId === "basic" && (
        <div className="space-y-4">
          <div className="flex justify-center">
            <Avatar className="size-20">
              <AvatarFallback>?</AvatarFallback>
            </Avatar>
          </div>
          <div className="space-y-1">
            <Input
              heading="Name"
              placeholder="Your name"
              value={data.name}
              onChange={(e) => { setData((d) => ({ ...d, name: e.target.value })); setErrors((e) => ({ ...e, name: "" })); }}
              aria-invalid={!!errors.name}
            />
            {errors.name && <p className="text-xs text-destructive">{errors.name}</p>}
          </div>
          <div className="space-y-1">
            <Input
              heading="Username"
              placeholder="username"
              value={data.username}
              onChange={(e) => { setData((d) => ({ ...d, username: e.target.value })); setErrors((e) => ({ ...e, username: "" })); }}
              aria-invalid={!!errors.username}
            />
            {errors.username && <p className="text-xs text-destructive">{errors.username}</p>}
          </div>
          <div className="space-y-1">
            <Textarea
              placeholder="Bio"
              value={data.bio}
              onChange={(e) => setData((d) => ({ ...d, bio: e.target.value }))}
              className="min-h-20"
            />
          </div>
        </div>
      )}
      {currentStepId === "contact" && (
        <div className="space-y-4">
          <div className="space-y-1">
            <Input
              heading="Email"
              type="email"
              placeholder="you@example.com"
              value={data.email}
              onChange={(e) => { setData((d) => ({ ...d, email: e.target.value })); setErrors((e) => ({ ...e, email: "" })); }}
              aria-invalid={!!errors.email}
            />
            {errors.email && <p className="text-xs text-destructive">{errors.email}</p>}
          </div>
          <div className="space-y-1">
            <Input
              heading="Phone"
              type="tel"
              placeholder="+1 234 567 8900"
              value={data.phone}
              onChange={(e) => setData((d) => ({ ...d, phone: e.target.value }))}
            />
          </div>
        </div>
      )}
      {currentStepId === "social" && (
        <div className="space-y-4">
          <div className="space-y-1">
            <Input
              heading="Website"
              placeholder="https://"
              value={data.website}
              onChange={(e) => { setData((d) => ({ ...d, website: e.target.value })); setErrors((e) => ({ ...e, website: "" })); }}
              aria-invalid={!!errors.website}
            />
            {errors.website && <p className="text-xs text-destructive">{errors.website}</p>}
          </div>
        </div>
      )}
      {currentStepId === "review" && (
        <div className="space-y-2 rounded-md border border-border bg-muted/30 p-4 text-sm">
          <p>
            <span className="text-muted-foreground">Name:</span>{" "}
            {data.name || "—"}
          </p>
          <p>
            <span className="text-muted-foreground">Username:</span>{" "}
            {data.username || "—"}
          </p>
          <p>
            <span className="text-muted-foreground">Email:</span>{" "}
            {data.email || "—"}
          </p>
          <p>
            <span className="text-muted-foreground">Phone:</span>{" "}
            {data.phone || "—"}
          </p>
          <p>
            <span className="text-muted-foreground">Website:</span>{" "}
            {data.website || "—"}
          </p>
        </div>
      )}

      <div className="mt-8 flex items-center justify-between">
        {step === 0 ? (
          <button
            type="button"
            onClick={() => setStep(steps.length - 1)}
            className="text-sm text-muted-foreground hover:text-foreground"
          >
            Skip to review
          </button>
        ) : (
          <button
            type="button"
            onClick={() => setStep((s) => s - 1)}
            className="text-sm text-muted-foreground hover:text-foreground"
          >
            Back
          </button>
        )}
        <Button
          variant="secondary"
          size="sm"
          onClick={goNext}
        >
          {isLast ? "Complete Setup" : "Continue"}
        </Button>
      </div>
    </div>
  );
}

settings-profile-7.source:
"use client";

import * as React from "react";
import { z } from "zod";
import { Pencil, Check, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { cn } from "@/lib/utils";

const fields = [
  { key: "name", label: "Name", value: "Jane Doe" },
  { key: "username", label: "Username", value: "jane" },
  { key: "email", label: "Email", value: "jane@example.com" },
  { key: "bio", label: "Bio", value: "" },
];

const fieldSchemas: Record<string, z.ZodType<string>> = {
  name: z.string().min(1, "Name is required"),
  username: z
    .string()
    .min(2, "Username must be at least 2 characters")
    .regex(
      /^[a-z0-9_-]+$/i,
      "Username can only contain letters, numbers, underscore and hyphen",
    ),
  email: z.string().min(1, "Email is required").email("Enter a valid email"),
  bio: z.string(),
};

export function SettingsProfile7() {
  const [editKey, setEditKey] = React.useState<string | null>(null);
  const [values, setValues] = React.useState(
    Object.fromEntries(fields.map((f) => [f.key, f.value])),
  );
  const [draft, setDraft] = React.useState("");
  const [error, setError] = React.useState("");

  const startEdit = (key: string, current: string) => {
    setEditKey(key);
    setDraft(current);
    setError("");
  };

  const saveEdit = () => {
    if (!editKey) return;
    const schema = fieldSchemas[editKey];
    if (schema) {
      const result = schema.safeParse(draft);
      if (!result.success) {
        setError(result.error.issues[0]?.message ?? "Invalid value");
        return;
      }
      setValues((prev) => ({ ...prev, [editKey]: result.data ?? draft }));
    } else {
      setValues((prev) => ({ ...prev, [editKey]: draft }));
    }
    setEditKey(null);
    setError("");
  };

  const cancelEdit = () => {
    setEditKey(null);
    setDraft("");
  };

  const handleKeyDown = (e: React.KeyboardEvent, key: string) => {
    if (e.key === "Enter") saveEdit();
    if (e.key === "Escape") cancelEdit();
  };

  return (
    <div className="mx-auto max-w-md rounded-lg border border-border bg-background p-4 shadow-sm">
      <div className="flex gap-4">
        <div className="relative shrink-0">
          <Avatar className="size-14 my-4">
            <AvatarFallback>JD</AvatarFallback>
          </Avatar>
          <Button
            variant="primary"
            size="sm"
            className="absolute top-0 right-0 size-6 rounded-full p-0"
            aria-label="Edit photo"
          >
            <Pencil className="size-3" />
          </Button>
        </div>
        <div className="min-w-0 flex-1 space-y-0">
          {fields.map((field, i) => (
            <div
              key={field.key}
              className={cn(
                "flex items-center justify-between gap-2 py-2",
                i > 0 && "border-t border-border",
              )}
            >
              <div className="min-w-0 flex-1">
                <p className="text-xs font-medium text-muted-foreground">
                  {field.label}
                </p>
                {editKey === field.key ? (
                  <div className="mt-0.5 space-y-1">
                    <div className="flex items-center gap-1">
                      <Input
                        value={draft}
                        onChange={(e) => {
                          setDraft(e.target.value);
                          setError("");
                        }}
                        onBlur={saveEdit}
                        onKeyDown={(e) => handleKeyDown(e, field.key)}
                        className="h-8 text-sm"
                        autoFocus
                        aria-invalid={!!error}
                      />
                      <Button
                        variant="primary"
                        size="sm"
                        className="size-8 p-0"
                        onClick={saveEdit}
                      >
                        <Check className="size-4" />
                      </Button>
                      <Button
                        variant="primary"
                        size="sm"
                        className="size-8 bg-transparent p-0 hover:bg-accent"
                        onClick={cancelEdit}
                      >
                        <X className="size-4" />
                      </Button>
                    </div>
                    {error && (
                      <p className="text-xs text-destructive">{error}</p>
                    )}
                  </div>
                ) : (
                  <button
                    type="button"
                    onClick={() =>
                      startEdit(field.key, values[field.key] ?? "")
                    }
                    className="group mt-0.5 flex w-full items-center gap-2 text-left text-sm font-medium"
                  >
                    <span
                      className={cn(
                        !values[field.key] && "text-muted-foreground",
                      )}
                    >
                      {values[field.key] || "Not set"}
                    </span>
                    <Pencil className="size-3.5 opacity-0 transition-opacity group-hover:opacity-100" />
                  </button>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

sheet.source:
"use client"

import * as React from "react"
import { XIcon } from "lucide-react"
import { Dialog as SheetPrimitive } from "radix-ui"

import { cn } from "@/lib/utils"

function Sheet({ ...props }: React.ComponentProps<typeof SheetPrimitive.Root>) {
  return <SheetPrimitive.Root data-slot="sheet" {...props} />
}

function SheetTrigger({
  ...props
}: React.ComponentProps<typeof SheetPrimitive.Trigger>) {
  return <SheetPrimitive.Trigger data-slot="sheet-trigger" {...props} />
}

function SheetClose({
  ...props
}: React.ComponentProps<typeof SheetPrimitive.Close>) {
  return <SheetPrimitive.Close data-slot="sheet-close" {...props} />
}

function SheetPortal({
  ...props
}: React.ComponentProps<typeof SheetPrimitive.Portal>) {
  return <SheetPrimitive.Portal data-slot="sheet-portal" {...props} />
}

function SheetOverlay({
  className,
  ...props
}: React.ComponentProps<typeof SheetPrimitive.Overlay>) {
  return (
    <SheetPrimitive.Overlay
      data-slot="sheet-overlay"
      className={cn(
        "fixed inset-0 z-50 bg-black/50 data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:animate-in data-[state=open]:fade-in-0",
        className
      )}
      {...props}
    />
  )
}

function SheetContent({
  className,
  children,
  side = "right",
  showCloseButton = true,
  ...props
}: React.ComponentProps<typeof SheetPrimitive.Content> & {
  side?: "top" | "right" | "bottom" | "left"
  showCloseButton?: boolean
}) {
  return (
    <SheetPortal>
      <SheetOverlay />
      <SheetPrimitive.Content
        data-slot="sheet-content"
        className={cn(
          "fixed z-50 flex flex-col gap-4 bg-background shadow-lg transition ease-in-out data-[state=closed]:animate-out data-[state=closed]:duration-300 data-[state=open]:animate-in data-[state=open]:duration-500",
          side === "right" &&
            "inset-y-0 right-0 h-full w-3/4 border-l data-[state=closed]:slide-out-to-right data-[state=open]:slide-in-from-right sm:max-w-sm",
          side === "left" &&
            "inset-y-0 left-0 h-full w-3/4 border-r data-[state=closed]:slide-out-to-left data-[state=open]:slide-in-from-left sm:max-w-sm",
          side === "top" &&
            "inset-x-0 top-0 h-auto border-b data-[state=closed]:slide-out-to-top data-[state=open]:slide-in-from-top",
          side === "bottom" &&
            "inset-x-0 bottom-0 h-auto border-t data-[state=closed]:slide-out-to-bottom data-[state=open]:slide-in-from-bottom",
          className
        )}
        {...props}
      >
        {children}
        {showCloseButton && (
          <SheetPrimitive.Close className="absolute top-4 right-4 rounded-xs opacity-70 ring-offset-background transition-opacity hover:opacity-100 focus:ring-2 focus:ring-ring focus:ring-offset-2 focus:outline-hidden disabled:pointer-events-none data-[state=open]:bg-secondary">
            <XIcon className="size-4" />
            <span className="sr-only">Close</span>
          </SheetPrimitive.Close>
        )}
      </SheetPrimitive.Content>
    </SheetPortal>
  )
}

function SheetHeader({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="sheet-header"
      className={cn("flex flex-col gap-1.5 p-4", className)}
      {...props}
    />
  )
}

function SheetFooter({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="sheet-footer"
      className={cn("mt-auto flex flex-col gap-2 p-4", className)}
      {...props}
    />
  )
}

function SheetTitle({
  className,
  ...props
}: React.ComponentProps<typeof SheetPrimitive.Title>) {
  return (
    <SheetPrimitive.Title
      data-slot="sheet-title"
      className={cn("font-semibold text-foreground", className)}
      {...props}
    />
  )
}

function SheetDescription({
  className,
  ...props
}: React.ComponentProps<typeof SheetPrimitive.Description>) {
  return (
    <SheetPrimitive.Description
      data-slot="sheet-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

export {
  Sheet,
  SheetTrigger,
  SheetClose,
  SheetContent,
  SheetHeader,
  SheetFooter,
  SheetTitle,
  SheetDescription,
}

